    /* ══════════════════════════════════════════════
       SKY + GROUND (bgCvs — every frame, fast)
    ══════════════════════════════════════════════ */

    function drawBg() {
        var ev=EVENTS[eventIndex];
        var rdH=H-GROUND;

        /* sky — ALWAYS light blue regardless of weather event.
           Weather elements (clouds, rain, lightning, meteors, etc.) still
           render on top in drawDynamic. */
        var sky=bgC.createLinearGradient(0,0,0,GROUND);
        sky.addColorStop(0, '#a8d6ff');
        sky.addColorStop(1, '#e6f3ff');
        bgC.fillStyle=sky; bgC.fillRect(0,0,W,H);

        /* sun is always present on the light blue sky */
        radialGlow(bgC, W*0.82,H*0.12, 90, 255,240,180, 0.30);
        radialGlow(bgC, W*0.82,H*0.12, 44, 255,250,210, 0.55);
        bgC.fillStyle='rgba(255,252,230,0.98)';
        bgC.beginPath(); bgC.arc(W*0.82,H*0.12,22,0,Math.PI*2); bgC.fill();

        /* overcast cloud wisps */
        var bgType=effType(ev);
        if(bgType==='snow'||bgType==='blizzard'||bgType==='rain') {
            bgC.fillStyle='rgba(255,255,255,0.22)';
            for(var ci=0;ci<6;ci++) {
                var cx2=(ci*W/5.5+40)%W, cy2=H*0.08+ci*H*0.03;
                bgC.beginPath(); bgC.ellipse(cx2,cy2,80+ci*20,18+ci*4,0,0,Math.PI*2); bgC.fill();
            }
        }

        /* heat glow disk */
        if(bgType==='heat') {
            radialGlow(bgC, W*0.15,H*0.09, 110, 255,140,40, 0.45);
            radialGlow(bgC, W*0.15,H*0.09,  55, 255,200,80, 0.65);
            bgC.fillStyle='rgba(255,220,100,0.98)';
            bgC.beginPath(); bgC.arc(W*0.15,H*0.09,20,0,Math.PI*2); bgC.fill();
        }

        /* road */
        bgC.fillStyle='#181820';
        bgC.fillRect(0,GROUND,W,rdH*0.52);

        /* road center dashes */
        bgC.strokeStyle='rgba(255,220,0,0.55)';
        bgC.setLineDash([22,14]); bgC.lineWidth=2;
        bgC.beginPath(); bgC.moveTo(0,GROUND+rdH*0.26); bgC.lineTo(W,GROUND+rdH*0.26); bgC.stroke();
        bgC.setLineDash([]);

        /* edge lines */
        bgC.strokeStyle='rgba(255,255,255,0.18)'; bgC.lineWidth=1.5;
        bgC.beginPath(); bgC.moveTo(0,GROUND+rdH*0.04); bgC.lineTo(W,GROUND+rdH*0.04); bgC.stroke();
        bgC.beginPath(); bgC.moveTo(0,GROUND+rdH*0.50); bgC.lineTo(W,GROUND+rdH*0.50); bgC.stroke();

        /* sidewalks */
        bgC.fillStyle='#14142a'; bgC.fillRect(0,GROUND+rdH*0.51,W,rdH*0.11);
        bgC.fillStyle='#121228'; bgC.fillRect(0,GROUND+rdH*0.80,W,rdH*0.20);

        /* street lamps + cone beams */
        for(var l=0;l<10;l++) {
            var lx=(l+0.5)*W/10;
            var ly=GROUND+rdH*0.51;
            /* cone beam */
            lampCone(bgC, lx, ly-rdH*0.46, 0);
            /* pavement glow pool */
            radialGlow(bgC, lx,ly+8, 38, 255,210,90, 0.20);
            /* post */
            bgC.strokeStyle='#22223c'; bgC.lineWidth=2;
            bgC.beginPath(); bgC.moveTo(lx,ly); bgC.lineTo(lx,GROUND+rdH*0.05); bgC.stroke();
            /* arm */
            bgC.beginPath(); bgC.moveTo(lx,GROUND+rdH*0.05); bgC.lineTo(lx+8,GROUND+rdH*0.03); bgC.stroke();
            /* bulb */
            bgC.fillStyle='rgba(255,218,100,0.95)';
            bgC.beginPath(); bgC.arc(lx+8,GROUND+rdH*0.03,3.5,0,Math.PI*2); bgC.fill();
        }

        /* river */
        bgC.fillStyle='#02050b';
        bgC.fillRect(0,GROUND+rdH,W,H-(GROUND+rdH));
        /* river shimmer */
        bgC.strokeStyle='rgba(30,60,120,0.25)'; bgC.lineWidth=1;
        for(var rw=0;rw<4;rw++) {
            var ry=GROUND+rdH+rw*8;
            bgC.beginPath(); bgC.moveTo(0,ry); bgC.lineTo(W,ry); bgC.stroke();
        }
    }

    /* ══════════════════════════════════════════════
       CITY LAYER (cached)
    ══════════════════════════════════════════════ */

    function drawCity() {
        if(cityBuilt) return;
        cityBuilt=true;
        cityC.clearRect(0,0,W,H);

        for(var i=0;i<BGBUILDS.length;i++) drawBgBuilding(cityC,BGBUILDS[i]);
        for(var i=0;i<LM.length;i++) LM[i].fn(cityC,LM[i].x,GROUND,LM[i].wins);
    }

    /* ══════════════════════════════════════════════
       VEHICLES — 5 types, realistic side profiles
    ══════════════════════════════════════════════ */

    var VEH_TYPES  = ['taxi','sedan','nypd','bus','truck'];
    var SEDAN_COLS = ['#c82020','#205ac8','#20a820','#c89020','#882088','#208888','#c0c0c0','#f0ece8'];

    function makeVehicle() {
        var type = VEH_TYPES[rngI(0,VEH_TYPES.length)];
        var dir  = rngI(0,2)===0 ? 1 : -1;
        return {
            type: type, x: rng(-200,W+200), dir: dir,
            speed: (type==='bus'||type==='truck') ? rng(0.5,1.4) : rng(1.0,2.8),
            baseSpeed: 0,
            lit: rng(0,1)<0.75,
            col: (type==='sedan') ? SEDAN_COLS[rngI(0,SEDAN_COLS.length)] : null,
            lightPhase: rng(0,Math.PI*2),
            wiperT: rng(0,Math.PI*2),
            hazT: rng(0,Math.PI*2),
            drift: 0,
            yOff: 0
        };
    }

    function initVehicles() {
        vehicles=[];
        for(var i=0;i<22;i++) {
            var v=makeVehicle();
            v.baseSpeed=v.speed;
            vehicles.push(v);
        }
    }

    function updateVehicles(dt) {
        var type=effType(EVENTS[eventIndex]);
        /* speed multiplier — bad weather slows traffic */
        var spMul = 1;
        if(type==='rain') spMul=0.65;
        else if(type==='storm') spMul=0.45;
        else if(type==='snow') spMul=0.55;
        else if(type==='blizzard') spMul=0.30;
        else if(type==='hail') spMul=0.45;
        else if(type==='flood') spMul=0.25;
        else if(type==='tornado') spMul=0.20;
        else if(type==='earthquake') spMul=0.15;
        else if(type==='meteor') spMul=0.35;
        else if(type==='bloodmoon') spMul=0.55;
        else if(type==='heat') spMul=0.75;
        else if(type==='wind') spMul=1.2;
        for(var i=0;i<vehicles.length;i++) {
            var v=vehicles[i];
            /* skip cars inside alien saucers — they don't drive */
            if (v._absHidden && !v._absLifting) { continue; }
            /* alien-car aging — counts toward shape-shift back to
               normal. After _alienizedDur, enter morph for _morphDur,
               then clear the flag. */
            if (v._alienized){
                v._alienizedT += dt;
                if (!v._morphing && v._alienizedT > v._alienizedDur){
                    v._morphing = true;
                    v._morphT = 0;
                }
                if (v._morphing){
                    v._morphT += dt;
                    if (v._morphT >= v._morphDur){
                        v._alienized = false;
                        v._morphing = false;
                        v._morphT = 0;
                    }
                }
            }
            v.x+=v.dir*v.speed*spMul*dt*0.055;
            v.lightPhase+=dt*0.005;
            v.wiperT+=dt*0.012;
            v.hazT+=dt*0.008;
            /* lateral drift in tornado / wind / earthquake */
            if(type==='tornado') {
                var dist=v.x-tX;
                v.drift += -Math.sign(dist)*Math.max(0,(200-Math.abs(dist))/200)*0.4*dt*0.02;
                v.x+=v.drift*dt*0.02;
            } else if(type==='wind') {
                v.drift = Math.sin(performance.now()*0.001 + v.x*0.01)*1.2;
            } else if(type==='earthquake') {
                v.yOff = Math.sin(performance.now()*0.025 + v.x*0.02)*1.4;
                v.xShake = Math.cos(performance.now()*0.030 + v.x*0.015)*1.2;
            } else {
                v.drift *= 0.95; v.yOff *= 0.9; v.xShake *= 0.9;
            }
            if(v.x>W+220) v.x=-220;
            if(v.x<-220)  v.x=W+220;
        }
    }

    /* tyre + hubcap */
    function drawWheel(c, cx, cy, r) {
        c.fillStyle='#181818';
        c.beginPath(); c.arc(cx,cy,r,0,Math.PI*2); c.fill();
        c.strokeStyle='rgba(100,100,100,0.50)'; c.lineWidth=r*0.16;
        c.beginPath(); c.arc(cx,cy,r*0.80,-2.1,-0.8); c.stroke();
        c.fillStyle='#a8a8a8';
        c.beginPath(); c.arc(cx,cy,r*0.44,0,Math.PI*2); c.fill();
        c.fillStyle='#787878';
        c.beginPath(); c.arc(cx,cy,r*0.14,0,Math.PI*2); c.fill();
    }

    /* realistic car body silhouette + glass
       d=1 → faces right (front is rightward), d=-1 → faces left
       fw/rw/bH/cH in pixels; cfi/cri = cabin inset from bumper; wsl/rgl = glass lean */
    function carProfile(c, x, by, d, fw, rw, bH, cH, cfi, cri, wsl, rgl, bodyCol, glassCol, outlineCol) {
        var xF   = x + d*fw;           /* front bumper */
        var xR   = x - d*rw;           /* rear bumper  */
        var xCF  = x + d*(fw-cfi);     /* windshield base (on hood) */
        var xCR  = x - d*(rw-cri);     /* rear-glass base (on trunk) */
        var xWF  = xCF - d*wsl;        /* windshield top (leans rearward) */
        var xWR  = xCR + d*rgl;        /* rear-glass top (leans forward) */
        var hY   = by - bH;            /* hood/trunk level */
        var rY   = hY - cH;            /* roofline */

        /* full body */
        c.fillStyle = bodyCol;
        c.beginPath();
        c.moveTo(xR, by);  c.lineTo(xF, by);    /* floor */
        c.lineTo(xF, hY);  c.lineTo(xCF, hY);   /* front bumper face + hood */
        c.lineTo(xWF, rY); c.lineTo(xWR, rY);   /* windshield + roof */
        c.lineTo(xCR, hY); c.lineTo(xR, hY);    /* rear glass + trunk */
        c.closePath(); c.fill();

        /* outline */
        c.strokeStyle = outlineCol||'rgba(0,0,0,0.38)'; c.lineWidth=0.9;
        c.beginPath();
        c.moveTo(xR,by); c.lineTo(xF,by); c.lineTo(xF,hY); c.lineTo(xCF,hY);
        c.lineTo(xWF,rY); c.lineTo(xWR,rY); c.lineTo(xCR,hY); c.lineTo(xR,hY);
        c.closePath(); c.stroke();

        /* glass */
        c.fillStyle = glassCol||'rgba(140,200,240,0.60)';
        c.beginPath();
        c.moveTo(xCR,hY); c.lineTo(xCF,hY);
        c.lineTo(xWF,rY); c.lineTo(xWR,rY);
        c.closePath(); c.fill();

        /* A-pillar */
        c.strokeStyle='rgba(0,0,0,0.28)'; c.lineWidth=1.1;
        c.beginPath(); c.moveTo(xCF,hY); c.lineTo(xWF,rY); c.stroke();
        /* C-pillar */
        c.beginPath(); c.moveTo(xCR,hY); c.lineTo(xWR,rY); c.stroke();
        /* B-pillar + door line */
        c.lineWidth=0.8;
        var bp=(xCF+xCR)/2;
        c.beginPath(); c.moveTo(bp,hY); c.lineTo(bp,by); c.stroke();

        return {xF:xF,xR:xR,xCF:xCF,xCR:xCR,xWF:xWF,xWR:xWR,hY:hY,rY:rY};
    }

    function drawVehicle(c, v) {
        var rdH = H-GROUND;
        var s   = Math.max(5, rdH*0.12);    /* scale unit */
        var wr  = Math.max(3, s*0.30);      /* wheel radius */
        /* lane split by direction so opposite-direction cars don't drive through each other */
        var laneOff = (v.dir===1) ? rdH*0.06 : -rdH*0.06;
        var by  = GROUND + rdH*0.10 + laneOff; /* body bottom */
        var wy  = by + wr*0.52;             /* wheel centre (half-embedded) */
        var d   = v.dir, x = v.x;

        if (v.type==='taxi') {
            var p = carProfile(c,x,by,d, s*0.96,s*0.96, s*0.42,s*0.46,
                               s*0.28,s*0.30, s*0.16,s*0.14,
                               '#f5c518','rgba(80,135,180,0.96)','#b89000');
            /* taxi roof sign */
            var sW=s*0.40, sH=s*0.17, sY=p.rY-sH-1;
            c.fillStyle='#fff'; c.fillRect(x-sW/2,sY,sW,sH);
            c.fillStyle='#222'; c.font='bold '+(s*0.13)+'px sans-serif'; c.textAlign='center';
            c.fillText('TAXI',x,sY+sH*0.82); c.textAlign='left';
            /* headlights */
            c.fillStyle='#fffce0'; c.fillRect(Math.min(p.xF,p.xF-d*2),by-p.hY>0?by-2:p.hY+2,2,s*0.18);
            if(v.lit) radialGlow(c,p.xF+d*2,by-s*0.20,s*0.80,255,248,200,0.32);
            /* taillights */
            c.fillStyle='#ff1800'; c.fillRect(Math.min(p.xR,p.xR+d*2),by-s*0.30,2,s*0.18);
            radialGlow(c,p.xR-d*2,by-s*0.22,s*0.30,255,20,0,0.22);
            drawWheel(c, x+d*s*0.50, wy, wr);
            drawWheel(c, x-d*s*0.50, wy, wr);

        } else if (v.type==='sedan') {
            var p = carProfile(c,x,by,d, s*0.90,s*0.90, s*0.36,s*0.44,
                               s*0.24,s*0.32, s*0.20,s*0.18,
                               v.col,'rgba(60,115,170,0.95)','rgba(0,0,0,0.36)');
            c.fillStyle='#fffce0'; c.fillRect(Math.min(p.xF,p.xF-d*2),by-s*0.26,2,s*0.16);
            if(v.lit) radialGlow(c,p.xF+d*2,by-s*0.18,s*0.78,255,248,200,0.28);
            c.fillStyle='#ff1000'; c.fillRect(Math.min(p.xR,p.xR+d*2),by-s*0.28,2,s*0.16);
            drawWheel(c, x+d*s*0.48, wy, wr);
            drawWheel(c, x-d*s*0.48, wy, wr);

        } else if (v.type==='nypd') {
            var p = carProfile(c,x,by,d, s*0.94,s*0.94, s*0.40,s*0.44,
                               s*0.26,s*0.30, s*0.15,s*0.13,
                               '#141418','rgba(45,90,140,0.95)','rgba(0,0,0,0.50)');
            /* white door panel */
            var dL=Math.min(p.xCF,p.xCR), dR=Math.max(p.xCF,p.xCR);
            c.fillStyle='#d8dcea'; c.fillRect(dL,p.hY,dR-dL,s*0.22);
            c.fillStyle='#141418'; c.font='bold '+(s*0.12)+'px sans-serif'; c.textAlign='center';
            c.fillText('NYPD',x,p.hY+s*0.20); c.textAlign='left';
            /* lightbar */
            var lb=Math.sin(v.lightPhase*3)>0;
            var lbW=s*0.58,lbH=s*0.11,lbX=x-lbW/2,lbY=p.rY-lbH;
            c.fillStyle='#1a1a1a'; c.fillRect(lbX,lbY,lbW,lbH);
            c.fillStyle=lb?'rgba(0,80,255,0.96)':'rgba(255,20,20,0.96)';
            c.fillRect(lbX+1,lbY+1,lbW/2-2,lbH-2);
            c.fillStyle=lb?'rgba(255,20,20,0.96)':'rgba(0,80,255,0.96)';
            c.fillRect(lbX+lbW/2+1,lbY+1,lbW/2-2,lbH-2);
            if(lb) radialGlow(c,x-lbW*0.25,lbY,s*0.75,0,80,255,0.45);
            else   radialGlow(c,x+lbW*0.25,lbY,s*0.75,255,20,20,0.45);
            c.fillStyle='#fffce0'; c.fillRect(Math.min(p.xF,p.xF-d*2),by-s*0.28,2,s*0.18);
            if(v.lit) radialGlow(c,p.xF+d*2,by-s*0.20,s*0.78,255,248,200,0.28);
            c.fillStyle='#ff0000'; c.fillRect(Math.min(p.xR,p.xR+d*2),by-s*0.28,2,s*0.18);
            drawWheel(c, x+d*s*0.50, wy, wr);
            drawWheel(c, x-d*s*0.50, wy, wr);

        } else if (v.type==='bus') {
            /* MTA bus — long flat box with angled front face */
            var bw=s*1.90, bh=s*1.55;
            var xL=x-bw, xR2=x+bw, bTop=by-bh;
            /* body */
            c.fillStyle='#1a3870';
            c.fillRect(xL,bTop,xR2-xL,bh);
            /* cream waist band */
            c.fillStyle='#cec8b4';
            c.fillRect(xL,bTop+bh*0.52,xR2-xL,bh*0.18);
            /* darker roof stripe */
            c.fillStyle='#102860';
            c.fillRect(xL,bTop,xR2-xL,bh*0.07);
            /* angled front face */
            var frontX = d===1 ? xR2 : xL;
            c.fillStyle='rgba(0,0,0,0.22)';
            c.beginPath();
            c.moveTo(frontX,bTop); c.lineTo(frontX+d*s*0.12,bTop+bh*0.25);
            c.lineTo(frontX+d*s*0.12,by); c.lineTo(frontX,by);
            c.closePath(); c.fill();
            /* windows — 7 evenly spaced */
            c.fillStyle='rgba(55,110,165,0.96)';
            var nw=7, wWin=(xR2-xL-s*0.50)/nw, wGap=s*0.10;
            for(var bi2=0;bi2<nw;bi2++) {
                var wx4=xL+s*0.25+bi2*(wWin+wGap);
                c.fillRect(wx4,bTop+bh*0.12,wWin-wGap,bh*0.32);
            }
            /* destination display at front */
            var destX2=d===1?xR2-s*0.55:xL+s*0.15;
            c.fillStyle='rgba(255,255,60,0.88)';
            c.fillRect(destX2,bTop+bh*0.10,s*0.35,bh*0.22);
            /* outline */
            c.strokeStyle='rgba(0,0,0,0.35)'; c.lineWidth=1.2;
            c.strokeRect(xL,bTop,xR2-xL,bh);
            /* MTA label */
            c.fillStyle='rgba(255,255,255,0.55)'; c.font='bold '+(s*0.15)+'px sans-serif'; c.textAlign='center';
            c.fillText('MTA',x,bTop+bh*0.46); c.textAlign='left';
            if(v.lit) radialGlow(c,frontX+d*s*0.14,by-bh*0.50,s*0.90,255,248,220,0.30);
            var bwr=wr*1.10;
            drawWheel(c, x+bw*0.68,  by+bwr*0.50, bwr);
            drawWheel(c, x+bw*0.10,  by+bwr*0.50, bwr);
            drawWheel(c, x-bw*0.68,  by+bwr*0.50, bwr);

        } else if (v.type==='truck') {
            /* box truck: cab at front, cargo box at rear */
            var tcW=s*0.70, tbW=s*1.50, tbH=s*1.12, tcH=s*0.82;
            var cabFront = x+d*tcW;   /* front bumper of cab */
            var boxRear  = x-d*tbW;   /* rear of cargo box  */
            /* cargo box */
            var bxL=Math.min(x,boxRear), bxW=Math.abs(x-boxRear);
            c.fillStyle='#b0a898'; c.fillRect(bxL,by-tbH,bxW,tbH);
            /* box door horizontal bands */
            c.strokeStyle='rgba(0,0,0,0.18)'; c.lineWidth=0.8;
            for(var dl2=1;dl2<3;dl2++) {
                c.beginPath(); c.moveTo(bxL+1,by-tbH*dl2/3); c.lineTo(bxL+bxW-1,by-tbH*dl2/3); c.stroke();
            }
            /* vertical rear door seam */
            var rearSeam=d===1?bxL+s*0.22:bxL+bxW-s*0.22;
            c.beginPath(); c.moveTo(rearSeam,by-tbH); c.lineTo(rearSeam,by); c.stroke();
            c.strokeStyle='rgba(0,0,0,0.25)'; c.lineWidth=1;
            c.strokeRect(bxL+0.5,by-tbH+0.5,bxW-1,tbH-1);
            /* company stripe */
            c.fillStyle='rgba(200,80,20,0.55)';
            c.fillRect(bxL,by-tbH*0.60,bxW,tbH*0.12);
            /* cab silhouette */
            c.fillStyle='#887c6e';
            c.beginPath();
            c.moveTo(x,by);
            c.lineTo(cabFront,by);
            c.lineTo(cabFront,by-tcH*0.62);   /* front lower */
            c.lineTo(cabFront-d*s*0.10,by-tcH);/* hood/windshield join */
            c.lineTo(x,by-tcH);               /* top at cab-box join */
            c.closePath(); c.fill();
            c.strokeStyle='rgba(0,0,0,0.30)'; c.lineWidth=1; c.stroke();
            /* cab windshield glass */
            c.fillStyle='rgba(130,192,228,0.65)';
            c.beginPath();
            c.moveTo(cabFront-d*s*0.06, by-tcH*0.64);
            c.lineTo(cabFront-d*s*0.14, by-tcH*0.96);
            c.lineTo(x+d*s*0.05,        by-tcH*0.93);
            c.lineTo(x+d*s*0.05,        by-tcH*0.63);
            c.closePath(); c.fill();
            /* headlights */
            c.fillStyle='#fffce0';
            c.fillRect(Math.min(cabFront,cabFront-d*2),by-tcH*0.30,2,s*0.16);
            if(v.lit) radialGlow(c,cabFront+d*2,by-tcH*0.22,s*0.80,255,248,220,0.26);
            /* taillights */
            c.fillStyle='#ff1800';
            c.fillRect(Math.min(boxRear,boxRear+d*2),by-tbH*0.36,2,s*0.18);
            /* wheels */
            var twr=wr*1.05;
            drawWheel(c, x+d*tcW*0.55, by+twr*0.52, twr);
            drawWheel(c, x-d*tbW*0.55, by+twr*0.52, twr);
            drawWheel(c, x-d*tbW*0.78, by+twr*0.52, twr);
        }
    }

    /* ══════════════════════════════════════════════
       PEDESTRIANS
    ══════════════════════════════════════════════ */

    function initPeds() {
        peds=[];
        for(var i=0;i<32;i++) {
            peds.push({
                x:   rng(0,W),
                dir: rngI(0,2)===0?1:-1,
                speed:rng(0.22,0.65),
                baseSpeed:0,
                t:   rng(0,Math.PI*2),
                coat:rngI(0,5),
                umbrellaCol: rngI(0,6),
                row: rngI(0,2),
                slipT: 0,
                fallT: 0,
                hat: rng(0,1)<0.35
            });
        }
        for(var pi=0;pi<peds.length;pi++) peds[pi].baseSpeed=peds[pi].speed;
    }

    function updatePeds(dt) {
        var type=effType(EVENTS[eventIndex]);
        /* pedestrians ALWAYS walk at normal speed — only outfit changes by weather */
        var sm = 1;
        for(var i=0;i<peds.length;i++) {
            var p=peds[i];
            /* abducted peds — held in the saucer's beam, no walking */
            if (p._absHidden || p._absLifting) { p.t+=dt*0.003; continue; }
            p.x+=p.dir*p.speed*sm*dt*0.038;
            p.t+=dt*0.003;
            if(type==='earthquake') {
                p.eqX = Math.cos(performance.now()*0.040 + p.x*0.05)*1.0;
                p.eqY = Math.sin(performance.now()*0.050 + p.x*0.04)*0.7;
            } else if(p.eqX||p.eqY) {
                p.eqX *= 0.85; p.eqY *= 0.85;
                if(Math.abs(p.eqX)<0.05) p.eqX=0;
                if(Math.abs(p.eqY)<0.05) p.eqY=0;
            }
            if(p.x>W+20) p.x=-20;
            if(p.x<-20)  p.x=W+20;
        }
    }

    function drawPeds(c) {
        var rdH=H-GROUND;
        var type=effType(EVENTS[eventIndex]);
        var COATS=['#c8cce0','#e0e4f0','#8898b0','#a0a8c0','#e8d0b0'];
        var UMB=['#c83838','#1e6cb8','#1e8c3c','#444444','#c0a020','#7030a0'];
        /* outfit-only changes — body pose & walking speed stay normal */
        var isWet=(type==='rain'||type==='storm');
        var isCold=(type==='snow'||type==='blizzard');
        var isHot=(type==='heat');
        for(var i=0;i<peds.length;i++) {
            var p=peds[i];
            /* skip peds currently hidden inside an alien ship; the
               abduction renderer draws them in the beam itself. */
            if (p._absHidden && !p._absLifting) continue;
            var rowOff=p.row*6;
            /* earthquake per-ped jitter */
            var eqX = p.eqX||0, eqY = p.eqY||0;
            if(eqX||eqY) { c.save(); c.translate(eqX, eqY); }
            var pedY=GROUND+rdH*0.58+rowOff;
            /* lifted by tractor beam — override y for vertical lift */
            if (p._absLifting && p._absY !== undefined) {
                pedY = p._absY;
            }
            var col=COATS[p.coat];

            var swing=Math.sin(p.t*4.5)*3;

            /* body */
            c.fillStyle=col;
            c.fillRect(p.x-2, pedY-13, 4, 8);
            /* head */
            var headX=p.x, headY=pedY-16;
            c.beginPath(); c.arc(headX,headY,3,0,Math.PI*2); c.fill();

            /* hat / hood in cold (outfit) */
            if(isCold || p.hat) {
                c.fillStyle = isCold ? '#5a3020' : '#222';
                c.fillRect(headX-3, headY-3, 6, 2);
            }

            /* scarf in cold (outfit) */
            if(isCold) {
                c.strokeStyle = '#c84050';
                c.lineWidth = 1.4;
                c.beginPath();
                c.moveTo(headX, headY+2);
                c.lineTo(headX - p.dir*5 + Math.sin(p.t*5)*1.5, headY+5);
                c.stroke();
            }

            /* arms — neutral walking pose */
            c.strokeStyle=col; c.lineWidth=1.4;
            if(isWet) {
                /* one arm up holding umbrella */
                c.beginPath(); c.moveTo(p.x,pedY-10); c.lineTo(p.x,pedY-15); c.stroke();
                c.beginPath(); c.moveTo(p.x,pedY-10); c.lineTo(p.x+2-swing,pedY-5); c.stroke();
            } else {
                c.beginPath(); c.moveTo(p.x,pedY-10); c.lineTo(p.x-2+swing*0.5,pedY-6); c.stroke();
                c.beginPath(); c.moveTo(p.x,pedY-10); c.lineTo(p.x+2-swing*0.5,pedY-6); c.stroke();
            }

            /* legs — always walking */
            c.beginPath(); c.moveTo(p.x,pedY-5); c.lineTo(p.x-2+swing,pedY); c.stroke();
            c.beginPath(); c.moveTo(p.x,pedY-5); c.lineTo(p.x+2-swing,pedY); c.stroke();

            /* umbrella (outfit) in wet weather */
            if(isWet) {
                var ux=p.x, uy=headY-6;
                c.fillStyle=UMB[p.umbrellaCol];
                c.beginPath();
                c.ellipse(ux, uy, 8, 4, 0, Math.PI, 0);
                c.fill();
                /* umbrella ribs */
                c.strokeStyle='rgba(0,0,0,0.4)'; c.lineWidth=0.6;
                c.beginPath(); c.moveTo(ux-8,uy); c.lineTo(ux-4,uy-2); c.stroke();
                c.beginPath(); c.moveTo(ux-4,uy-2); c.lineTo(ux,uy-3); c.stroke();
                c.beginPath(); c.moveTo(ux,uy-3); c.lineTo(ux+4,uy-2); c.stroke();
                c.beginPath(); c.moveTo(ux+4,uy-2); c.lineTo(ux+8,uy); c.stroke();
                /* shaft to hand */
                c.strokeStyle='#222'; c.lineWidth=0.8;
                c.beginPath(); c.moveTo(ux,uy); c.lineTo(p.x,pedY-10); c.stroke();
            }

            /* heat sweat drops (outfit-ish atmospheric) */
            if(isHot && Math.random()<0.04) {
                c.fillStyle='rgba(120,180,220,0.7)';
                c.beginPath(); c.arc(headX+3, headY+2, 1, 0, Math.PI*2); c.fill();
            }
            if(eqX||eqY) c.restore();
        }
    }

    /* ══════════════════════════════════════════════
       PARTICLE SYSTEM
    ══════════════════════════════════════════════ */

    var eqShakeX=0, eqShakeY=0, eqTimer=0;  /* earthquake shake state */
    var meteorTrails=[];                      /* falling meteors */
    var auroraT=0;                            /* aurora animation time */
    var starField=[];                         /* static star positions */
    var shootingStars=[];                     /* animated shooting stars */
    var fireworksBursts=[];                   /* firework burst particles */
    var fwLaunchers=[];                       /* firework launch timers */
    var nebulaT=0;                            /* nebula animation time */
    var bloodMoonT=0;                         /* blood moon pulse time */

    function buildStarField() {
        starField=[];
        for(var si=0;si<320;si++) {
            starField.push({
                x: rng(0,W), y: rng(0,GROUND*0.85),
                r: rng(0.4,2.2),
                bright: rng(0.4,1.0),
                twinkleSpeed: rng(0.0008,0.003),
                twinkleOffset: rng(0,Math.PI*2)
            });
        }
    }
    function makeShootingStar() {
        var sx=rng(0,W*0.7), sy=rng(0,GROUND*0.4);
        return { x:sx, y:sy, vx:rng(4,12), vy:rng(2,7),
                 len:rng(60,180), r:rng(1,2.5),
                 life:0, maxLife:rng(600,1400),
                 col:rngI(0,3) /* 0=white,1=cyan,2=gold */ };
    }
    function makeFireworkBurst(x,y) {
        var burst=[], colType=rngI(0,6);
        var cols=[
            [255,80,80],[80,200,255],[255,200,60],
            [180,80,255],[80,255,180],[255,140,60]
        ];
        var c3=cols[colType];
        for(var pi=0;pi<55;pi++) {
            var angle=rng(0,Math.PI*2), speed=rng(1.5,6);
            burst.push({ x:x,y:y, vx:Math.cos(angle)*speed, vy:Math.sin(angle)*speed,
                         life:0, maxLife:rng(600,1100), r:rng(1,3),
                         rr:c3[0],gg:c3[1],bb:c3[2], gravity:0.04 });
        }
        return burst;
    }

    /* ═══════════════════════════════════════════════════════════
       INVENTED CATASTROPHE EVENT MODULE
       ───────────────────────────────────────────────────────────
       Self-contained init / update / draw for the 10 made-up
       weather events (tsunami, fireball shower, sulfuric acid
       rain, gravity well, crystal storm, locust swarm, lava rain,
       plasma storm, cosmic ray, quantum glitch). Hooks into
       initEvent, updateParticles, drawDynamic via three calls.
       Each event renders entirely from its own state arrays so
       the existing particle pipeline isn't disturbed.
       ═══════════════════════════════════════════════════════════ */

    var tsunamiState  = null;
    var mirrorShards  = [];
    var mirrorPrisms  = [];     /* drifting rainbow speck reflections */
    var acidDrops     = [];
    var acidSplats    = [];
    var acidPools     = [];     /* corroded ground patches (bubbling) */
    var acidSteam     = [];     /* steam wisps rising from acid */
    var acidDripFalls = [];     /* drips running down building edges */
    var gravityState  = null;
    var gravityDebris = [];     /* torn building pieces being pulled in */
    var gravityBeams  = [];     /* tractor beams to tallest structures */
    var gravityRings  = [];     /* shockwave distortion rings */
    var crystals      = [];
    var crystalGlitter= [];
    var stuckCrystals = [];     /* crystals embedded in buildings / cars */
    var locusts       = [];
    var lavaDrops     = [];
    var lavaSplats    = [];
    var lavaFires     = [];     /* burning fires on ground + buildings */
    var lavaEmbers    = [];     /* floating embers rising from fires */
    var lavaCraters   = [];     /* ground burn scars */
    var lavaSmoke     = [];     /* smoke plumes from fires */
    var plasmaArcs    = [];
    var plasmaTimer   = 0;
    var plasmaImpacts = [];     /* electric strike scorch points */
    var plasmaSparks  = [];     /* spark showers from impacts */
    var plasmaSmoke   = [];     /* smoke from electrocuted structures */
    var cosmicBeams   = [];
    var cosmicSparks  = [];
    var cosmicImpacts = [];     /* vaporization strike sites */
    var cosmicVapor   = [];     /* disintegration particles rising */
    var glitchPixels  = [];
    var glitchBars    = [];
    var glitchTimer   = 0;

    /* Pick a real destructible target — a building rooftop or a moving
       vehicle — so lava / plasma / cosmic / crystal impacts land on
       something solid in the scene, not in empty sky. Returns
       { x, y, kind } where kind ∈ {'building','car'}. */
    function pickImpactTarget() {
        var useCar = (typeof vehicles !== 'undefined' && vehicles.length > 0)
                     && Math.random() < 0.35;
        if (useCar) {
            var v = vehicles[rngI(0, vehicles.length)];
            var rdH = H - GROUND;
            var cs  = Math.max(5, rdH*0.12);
            var laneOff = (v.dir===1) ? rdH*0.06 : -rdH*0.06;
            var cy = GROUND + rdH*0.10 + laneOff - cs*0.55;
            return { x: v.x + (v.xShake||0), y: cy + (v.yOff||0), kind: 'car' };
        }
        if (typeof BGBUILDS !== 'undefined' && BGBUILDS.length) {
            var b = BGBUILDS[rngI(0, BGBUILDS.length)];
            var bx = b.x + rng(b.w*0.2, b.w*0.8);
            var by = GROUND - b.h - 2;
            return { x: bx, y: by, kind: 'building' };
        }
        return { x: rng(W*0.1, W*0.9), y: GROUND - 40, kind: 'building' };
    }

    function initCustomEvent(type) {
        tsunamiState  = null;
        mirrorShards  = [];
        mirrorPrisms  = [];
        acidDrops     = [];
        acidSplats    = [];
        acidPools     = [];
        acidSteam     = [];
        acidDripFalls = [];
        gravityState  = null;
        gravityDebris = [];
        gravityBeams  = [];
        gravityRings  = [];
        crystals      = [];
        crystalGlitter= [];
        stuckCrystals = [];
        locusts       = [];
        lavaDrops     = [];
        lavaSplats    = [];
        lavaFires     = [];
        lavaEmbers    = [];
        lavaCraters   = [];
        lavaSmoke     = [];
        plasmaArcs    = [];
        plasmaTimer   = 0;
        plasmaImpacts = [];
        plasmaSparks  = [];
        plasmaSmoke   = [];
        cosmicBeams   = [];
        cosmicSparks  = [];
        cosmicImpacts = [];
        cosmicVapor   = [];
        glitchPixels  = [];
        glitchBars    = [];
        glitchTimer   = 0;

        if (type === 'tsunami') {
            /* Full water-space scene:
                - waterLevel rises from below GROUND toward targetLevel
                - three sine-displaced wave layers at different y, speed
                  and phase for parallax depth
                - foam crests bloom along the front wave
                - bubbles rise from the dark depths
                - debris (planks) float on the surface */
            /* Water bounds per user spec:
                 - START just ABOVE the road (so the flood is visible
                   from the moment the event begins, not hidden behind
                   the pavement)
                 - PEAK at HALF the tallest building's rooftop height
                   (so the tsunami visibly engulfs the lower city)
               Tallest building is read from BGBUILDS (h is each
               building's height in pixels above GROUND). */
            var tallestH = 200;
            if (typeof BGBUILDS !== 'undefined' && BGBUILDS.length) {
                for (var bi=0; bi<BGBUILDS.length; bi++) {
                    if (BGBUILDS[bi].h > tallestH) tallestH = BGBUILDS[bi].h;
                }
            }
            tsunamiState = {
                t: 0,
                waterLevel:  GROUND - 8,                  /* start: just above the road */
                targetLevel: GROUND - tallestH * 0.5,     /* peak: half the tallest building */
                wavePhase1:  0,
                wavePhase2:  Math.PI*0.7,
                wavePhase3:  Math.PI*1.3,
                bubbles:     [],
                debris:      [],
                foamCrests:  [],
                splashSparks:[]
            };
            for (var b=0; b<28; b++) tsunamiState.bubbles.push({
                x: rng(0, W),
                y: GROUND + rng(20, H*0.4),
                r: rng(1.5, 5),
                vy: rng(-0.8, -2.0),
                drift: rng(-0.4, 0.4)
            });
            for (var dd=0; dd<10; dd++) tsunamiState.debris.push({
                x: rng(0, W),
                y: GROUND + rng(0, 20),
                w: rng(20, 60), h: rng(6, 12),
                rot: rng(-0.4, 0.4), rotV: rng(-0.003, 0.003),
                phase: rng(0, Math.PI*2)
            });
        } else if (type === 'mirrorRain') {
            for (var i=0; i<70; i++) mirrorShards.push({
                x: rng(0,W), y: rng(-H, GROUND-40),
                vy: rng(3, 7), vx: rng(-1.4, 0.6),
                w: rng(4, 12), h: rng(14, 36),
                angle: rng(-Math.PI/2, Math.PI/2),
                spin: rng(-0.04, 0.04),
                shimmer: rng(0, Math.PI*2),
                shimmerR: rng(0.06, 0.12)
            });
            for (var i=0; i<120; i++) mirrorPrisms.push({
                x: rng(0,W), y: rng(0, GROUND),
                vy: rng(0.3, 1.0), vx: rng(-0.2, 0.2),
                hue: rng(0, 360),
                hueDrift: rng(-30, 30),
                life: 0, maxLife: rng(700, 1600),
                size: rng(2, 5)
            });
        } else if (type === 'acidRain') {
            for (var i=0; i<240; i++) acidDrops.push({
                x: rng(0,W), y: rng(-H, GROUND),
                vy: rng(6,12), vx: rng(-1.4,0.4),
                len: rng(10,18)
            });
        } else if (type === 'gravityWell') {
            var debris = [];
            for (var i=0; i<120; i++) debris.push({
                angle: rng(0, Math.PI*2),
                radius: rng(80, 240),
                speed: rng(0.005, 0.015),
                spiral: rng(0.03, 0.10),
                size: rng(1, 3.5),
                hue: rngI(0, 3)   /* 0=white, 1=violet, 2=orange */
            });
            gravityState = {
                cx: W*0.72, cy: GROUND*0.28,
                r: 48, t: 0, debris: debris
            };
            /* Tractor beams aimed at 4 imaginary "tall buildings"
               along the lower city silhouette — each beam pulls a
               stream of building debris up into the well. */
            for (var b=0; b<4; b++) gravityBeams.push({
                bx: W*(0.12 + b*0.22) + rng(-30, 30),
                by: GROUND - rng(60, 180),    /* nominal rooftop y */
                pulse: rng(0, Math.PI*2),
                emitTimer: rng(0, 200)
            });
        } else if (type === 'crystalStorm') {
            for (var i=0; i<80; i++) crystals.push({
                x: rng(0,W), y: rng(-H, GROUND-50),
                vy: rng(0.6, 2.2), vx: rng(-0.4, 0.4),
                r: rng(5, 12),
                angle: rng(0, Math.PI*2),
                spin: rng(-0.02, 0.02),
                shine: rng(0, Math.PI*2)
            });
            for (var i=0; i<120; i++) crystalGlitter.push({
                x: rng(0,W), y: rng(0, GROUND),
                life: rng(0, 1000), maxLife: rng(400, 1200)
            });
        } else if (type === 'locustSwarm') {
            for (var i=0; i<180; i++) locusts.push({
                x: rng(-W*0.3, W*1.3), y: rng(H*0.08, GROUND-60),
                vx: rng(2.5, 5.5), vy: rng(-0.4, 0.4),
                wing: rng(0, Math.PI*2),
                wingRate: rng(0.05, 0.10),
                size: rng(2, 4)
            });
        } else if (type === 'lavaRain') {
            for (var i=0; i<90; i++) lavaDrops.push({
                x: rng(0,W), y: -rng(40, H*0.7),
                vy: rng(5, 10), vx: rng(-0.5, 0.5),
                r: rng(3, 7), trail: []
            });
        } else if (type === 'plasmaStorm') {
            /* arcs spawn dynamically in update */
        } else if (type === 'cosmicRay') {
            /* multi-hue beam palette so each beam is a different
               cosmic colour (cyan, magenta, lime, gold, violet…) */
            var beamCols = ['rgb(180,220,255)','rgb(255,170,220)',
                            'rgb(170,255,200)','rgb(255,220,120)',
                            'rgb(200,170,255)','rgb(140,240,255)',
                            'rgb(255,180,140)','rgb(220,255,170)'];
            for (var i=0; i<6; i++) cosmicBeams.push({
                x: rng(W*0.08, W*0.92),
                alpha: rng(0.35, 0.70),
                w: rng(24, 64),
                pulse: rng(0, Math.PI*2),
                pulseRate: rng(0.0008, 0.0022),
                col: beamCols[i % beamCols.length]
            });
            for (var i=0; i<120; i++) cosmicSparks.push({
                x: rng(0,W), y: rng(0, GROUND),
                vy: rng(2.5, 5.5), life: 0, maxLife: rng(500, 1400),
                col: beamCols[rngI(0, beamCols.length)]
            });
        } else if (type === 'quantumGlitch') {
            for (var i=0; i<140; i++) glitchPixels.push({
                x: rng(0,W), y: rng(0, GROUND),
                size: rngI(2, 8),
                col: ['#ff0044','#00ff88','#00ddff','#ffff00','#ff00ff'][rngI(0,5)],
                next: rng(50, 400)
            });
        }
    }

    /* Advance all per-event state. Called each frame after the
       existing particle update. */
    function updateCustomEvent(dt) {
        var type = effType(EVENTS[eventIndex]);
        var k = dt/16;

        if (type === 'tsunami' && tsunamiState) {
            var ts = tsunamiState;
            ts.t += dt;
            /* ease water level toward target */
            ts.waterLevel += (ts.targetLevel - ts.waterLevel) * 0.012 * k;
            /* advance wave phases at different speeds */
            ts.wavePhase1 += 0.0040 * dt;
            ts.wavePhase2 += 0.0028 * dt;
            ts.wavePhase3 += 0.0018 * dt;
            /* bubbles rising from the depths */
            for (var i=0; i<ts.bubbles.length; i++) {
                var bb = ts.bubbles[i];
                bb.y += bb.vy*k;
                bb.x += bb.drift*k;
                if (bb.y < ts.waterLevel - 4) {
                    bb.x = rng(0, W);
                    bb.y = GROUND + rng(20, H*0.4);
                    bb.r = rng(1.5, 5);
                    bb.vy = rng(-0.8, -2.0);
                }
            }
            /* debris floats with a sine bob along the surface */
            for (var i=0; i<ts.debris.length; i++) {
                var dz = ts.debris[i];
                dz.x += 0.5 * k;
                dz.phase += 0.005 * dt;
                dz.rot += dz.rotV * dt;
                if (dz.x > W + 80) dz.x = -80;
            }
            /* spawn foam at the leading crest */
            if (Math.random() < 0.55) {
                var fx = rng(0, W);
                var fy = ts.waterLevel + Math.sin(fx*0.025 + ts.wavePhase1)*8;
                ts.foamCrests.push({
                    x: fx, y: fy,
                    vx: rng(-0.6, 0.6), vy: rng(-1.4, -0.2),
                    life: 0, maxLife: rng(400, 900), r: rng(2, 5)
                });
            }
            for (var i=ts.foamCrests.length-1; i>=0; i--) {
                var f = ts.foamCrests[i];
                f.x += f.vx*k; f.y += f.vy*k; f.vy += 0.04*k; f.life += dt;
                if (f.life > f.maxLife) ts.foamCrests.splice(i,1);
            }
            /* occasional splash spark when a wave peaks against an obstacle */
            if (Math.random() < 0.08) {
                ts.splashSparks.push({
                    x: rng(W*0.1, W*0.9),
                    y: ts.waterLevel + rng(-20, 0),
                    vx: rng(-2, 2), vy: rng(-3, -1),
                    life: 0, maxLife: rng(300, 700)
                });
            }
            for (var i=ts.splashSparks.length-1; i>=0; i--) {
                var sk = ts.splashSparks[i];
                sk.x += sk.vx*k; sk.y += sk.vy*k; sk.vy += 0.10*k; sk.life += dt;
                if (sk.life > sk.maxLife) ts.splashSparks.splice(i,1);
            }
        }

        else if (type === 'mirrorRain') {
            for (var i=0; i<mirrorShards.length; i++) {
                var ms = mirrorShards[i];
                ms.x += ms.vx*k; ms.y += ms.vy*k;
                ms.angle += ms.spin*k;
                ms.shimmer += ms.shimmerR * dt;
                if (ms.y > GROUND - 10) {
                    /* spawn a burst of rainbow specks at impact */
                    for (var p=0; p<5; p++) mirrorPrisms.push({
                        x: ms.x + rng(-8, 8),
                        y: GROUND - rng(0, 6),
                        vy: rng(-0.6, 0.4), vx: rng(-1.2, 1.2),
                        hue: rng(0, 360),
                        hueDrift: rng(-90, 90),
                        life: 0, maxLife: rng(400, 900),
                        size: rng(2, 4)
                    });
                    ms.y = rng(-80, -10);
                    ms.x = rng(0, W);
                    ms.w = rng(4, 12); ms.h = rng(14, 36);
                    ms.angle = rng(-Math.PI/2, Math.PI/2);
                }
            }
            for (var i=0; i<mirrorPrisms.length; i++) {
                var pr = mirrorPrisms[i];
                pr.x += pr.vx*k; pr.y += pr.vy*k; pr.life += dt;
                pr.hue = (pr.hue + pr.hueDrift*dt*0.001) % 360;
                if (pr.life > pr.maxLife) {
                    pr.x = rng(0, W);
                    pr.y = rng(0, GROUND);
                    pr.vy = rng(0.3, 1.0); pr.vx = rng(-0.2, 0.2);
                    pr.life = 0; pr.maxLife = rng(700, 1600);
                    pr.hue = rng(0, 360);
                    pr.size = rng(2, 5);
                }
            }
        }

        else if (type === 'acidRain') {
            for (var i=0; i<acidDrops.length; i++) {
                var a = acidDrops[i];
                a.x += a.vx*k; a.y += a.vy*k;
                if (a.y >= GROUND) {
                    acidSplats.push({ x: a.x, y: GROUND, r: 0,
                                      maxR: rng(6, 14), life: 0,
                                      maxLife: rng(500, 1100) });
                    /* every few splats, spawn a corrosion pool that
                       persists and bubbles */
                    if (Math.random() < 0.28 && acidPools.length < 36) {
                        acidPools.push({
                            x: a.x + rng(-4, 4), y: GROUND,
                            r: rng(8, 18),
                            life: 0, maxLife: rng(5000, 12000),
                            bubble: rng(0, Math.PI*2)
                        });
                    }
                    /* steam wisp rising from the corrosion */
                    if (Math.random() < 0.45 && acidSteam.length < 80) {
                        acidSteam.push({
                            x: a.x, y: GROUND - 4,
                            vy: rng(-0.6, -1.4), vx: rng(-0.2, 0.2),
                            r: rng(3, 7), maxR: rng(12, 24),
                            life: 0, maxLife: rng(1400, 2800)
                        });
                    }
                    a.y = rng(-60, -10); a.x = rng(0, W);
                }
            }
            for (var i=acidSplats.length-1; i>=0; i--) {
                acidSplats[i].life += dt;
                acidSplats[i].r = acidSplats[i].maxR *
                                  (acidSplats[i].life/acidSplats[i].maxLife);
                if (acidSplats[i].life >= acidSplats[i].maxLife)
                    acidSplats.splice(i, 1);
            }
            /* corrosion pools — bubble + slowly fade */
            for (var i=acidPools.length-1; i>=0; i--) {
                acidPools[i].life += dt;
                acidPools[i].bubble += 0.005 * dt;
                if (acidPools[i].life >= acidPools[i].maxLife)
                    acidPools.splice(i, 1);
            }
            /* steam wisps grow as they rise */
            for (var i=acidSteam.length-1; i>=0; i--) {
                var st = acidSteam[i];
                st.x += st.vx*k; st.y += st.vy*k; st.life += dt;
                st.r = Math.min(st.maxR, st.r + 0.025*k);
                if (st.life >= st.maxLife) acidSteam.splice(i, 1);
            }
            /* drips running down imaginary building edges — every so
               often spawn a column of melting paint sliding toward
               the ground */
            if (Math.random() < 0.18 && acidDripFalls.length < 24) {
                acidDripFalls.push({
                    x: rng(W*0.05, W*0.95),
                    y: rng(GROUND*0.20, GROUND*0.70),
                    vy: rng(0.4, 1.2),
                    len: rng(20, 60),
                    grew: 0,
                    maxGrow: rng(60, 200),
                    /* melting paint colour — sampled from car/building
                       palette (red, yellow, blue, beige, brown) */
                    col: ['rgba(200,80,40,',
                          'rgba(220,200,80,',
                          'rgba(60,110,180,',
                          'rgba(180,160,120,',
                          'rgba(120,80,40,'][rngI(0,5)]
                });
            }
            for (var i=acidDripFalls.length-1; i>=0; i--) {
                var dr = acidDripFalls[i];
                dr.y += dr.vy*k;
                dr.grew += dr.vy*k;
                if (dr.y > GROUND || dr.grew > dr.maxGrow) {
                    acidDripFalls.splice(i, 1);
                }
            }
        }

        else if (type === 'gravityWell' && gravityState) {
            var gs = gravityState;
            gs.t += dt;
            for (var i=0; i<gs.debris.length; i++) {
                var d = gs.debris[i];
                d.angle += d.speed*k;
                d.radius -= d.spiral*k;
                if (d.radius < gs.r*0.4) {
                    d.angle = rng(0, Math.PI*2);
                    d.radius = rng(180, 280);
                }
            }
            /* shockwave rings emit periodically */
            if (Math.random() < 0.012) gravityRings.push({
                r: gs.r*0.5, life: 0, maxLife: 1400,
                strength: rng(0.5, 1.0)
            });
            for (var i=gravityRings.length-1; i>=0; i--) {
                var gr = gravityRings[i];
                gr.life += dt;
                gr.r += 0.05*dt;
                if (gr.life > gr.maxLife) gravityRings.splice(i, 1);
            }
            /* tractor beams pull building debris from each beam target
               toward the singularity */
            for (var b=0; b<gravityBeams.length; b++) {
                var gb = gravityBeams[b];
                gb.pulse += 0.003*dt;
                gb.emitTimer -= dt;
                if (gb.emitTimer <= 0) {
                    gb.emitTimer = rng(60, 220);
                    gravityDebris.push({
                        x: gb.bx + rng(-8, 8),
                        y: gb.by + rng(-4, 4),
                        targetX: gs.cx, targetY: gs.cy,
                        progress: 0,
                        speed: rng(0.0006, 0.0014),
                        size: rng(2, 6),
                        rot: rng(0, Math.PI*2),
                        rotV: rng(-0.005, 0.005),
                        col: rngI(0, 3)  /* 0=grey, 1=brown, 2=tan */
                    });
                }
            }
            /* fly building debris along curved bezier path toward the well */
            for (var i=gravityDebris.length-1; i>=0; i--) {
                var bd = gravityDebris[i];
                bd.progress += bd.speed * dt;
                bd.rot += bd.rotV * dt;
                if (bd.progress >= 1) {
                    gravityDebris.splice(i, 1);
                    continue;
                }
                /* shrink as it falls in (spaghettification) */
            }
        }

        else if (type === 'crystalStorm') {
            for (var i=0; i<crystals.length; i++) {
                var cz = crystals[i];
                cz.y += cz.vy*k; cz.x += cz.vx*k;
                cz.angle += cz.spin*k; cz.shine += 0.005*dt;
                /* A small fraction of falling crystals "stick" into an
                   ACTUAL target — a building rooftop or a moving car.
                   The shard inherits the target's position so it
                   visibly embeds in the structure, not in empty sky. */
                if (Math.random() < 0.0040 && stuckCrystals.length < 70) {
                    var tg = pickImpactTarget();
                    stuckCrystals.push({
                        x: tg.x, y: tg.y,
                        r: cz.r * 0.85,
                        angle: cz.angle,
                        shine: rng(0, Math.PI*2),
                        born: 0,
                        onCar: tg.kind === 'car'
                    });
                    cz.y = rng(-60, -10); cz.x = rng(0, W);
                    continue;
                }
                if (cz.y > GROUND) {
                    /* a crystal hitting the ground also has a chance to
                       embed at street level — looks like glass shards on
                       the road */
                    if (Math.random() < 0.45 && stuckCrystals.length < 80) {
                        stuckCrystals.push({
                            x: cz.x, y: GROUND - rng(0, 4),
                            r: cz.r * 0.7,
                            angle: rng(-0.8, 0.8),
                            shine: rng(0, Math.PI*2),
                            born: 0
                        });
                    }
                    cz.y = rng(-60, -10); cz.x = rng(0, W);
                }
            }
            for (var i=0; i<crystalGlitter.length; i++) {
                crystalGlitter[i].life += dt;
                if (crystalGlitter[i].life > crystalGlitter[i].maxLife) {
                    crystalGlitter[i].x = rng(0, W);
                    crystalGlitter[i].y = rng(0, GROUND);
                    crystalGlitter[i].life = 0;
                    crystalGlitter[i].maxLife = rng(400, 1200);
                }
            }
            /* age the embedded crystals so they slowly twinkle */
            for (var i=0; i<stuckCrystals.length; i++) {
                stuckCrystals[i].born += dt;
                stuckCrystals[i].shine += 0.004*dt;
            }
        }

        else if (type === 'locustSwarm') {
            for (var i=0; i<locusts.length; i++) {
                var lc = locusts[i];
                lc.x += lc.vx*k; lc.y += lc.vy*k;
                lc.wing += lc.wingRate*k;
                if (lc.x > W + 30) { lc.x = -30; lc.y = rng(H*0.08, GROUND-60); }
            }
        }

        else if (type === 'lavaRain') {
            for (var i=0; i<lavaDrops.length; i++) {
                var lv = lavaDrops[i];
                lv.x += lv.vx*k; lv.y += lv.vy*k; lv.vy += 0.05*k;
                lv.trail.unshift({ x: lv.x, y: lv.y, life: 0 });
                if (lv.trail.length > 8) lv.trail.pop();
                for (var t=0; t<lv.trail.length; t++) lv.trail[t].life += dt;
                /* periodically a drop "hits a building / car" — start
                   a fire on the actual target instead of in empty sky */
                if (Math.random() < 0.0020 && lavaFires.length < 22) {
                    var tg = pickImpactTarget();
                    lavaFires.push({
                        x: tg.x, y: tg.y,
                        size: rng(10, 18), life: 0,
                        maxLife: rng(4000, 8000),
                        flicker: rng(0, Math.PI*2),
                        onBuilding: tg.kind === 'building',
                        onCar: tg.kind === 'car'
                    });
                    lv.y = rng(-60, -10); lv.x = rng(0, W);
                    lv.vy = rng(5, 10); lv.trail.length = 0;
                    continue;
                }
                if (lv.y >= GROUND) {
                    lavaSplats.push({ x: lv.x, y: GROUND, r: 0,
                                      maxR: rng(8, 18), life: 0,
                                      maxLife: rng(900, 1800) });
                    /* ground fire on impact */
                    if (Math.random() < 0.45 && lavaFires.length < 30) {
                        lavaFires.push({
                            x: lv.x, y: GROUND - 2,
                            size: rng(8, 16), life: 0,
                            maxLife: rng(3000, 6000),
                            flicker: rng(0, Math.PI*2),
                            onBuilding: false
                        });
                    }
                    /* permanent crater scar */
                    if (lavaCraters.length < 80) lavaCraters.push({
                        x: lv.x, y: GROUND,
                        r: rng(5, 12),
                        born: 0
                    });
                    lv.y = rng(-60, -10); lv.x = rng(0, W);
                    lv.vy = rng(5, 10); lv.trail.length = 0;
                }
            }
            for (var i=lavaSplats.length-1; i>=0; i--) {
                lavaSplats[i].life += dt;
                lavaSplats[i].r = lavaSplats[i].maxR *
                                  Math.min(1, lavaSplats[i].life/600);
                if (lavaSplats[i].life >= lavaSplats[i].maxLife)
                    lavaSplats.splice(i, 1);
            }
            /* burning fires spawn embers + smoke */
            for (var i=0; i<lavaFires.length; i++) {
                var lf = lavaFires[i];
                lf.life += dt;
                lf.flicker += 0.012 * dt;
                if (Math.random() < 0.18 && lavaEmbers.length < 200) {
                    lavaEmbers.push({
                        x: lf.x + rng(-lf.size*0.4, lf.size*0.4),
                        y: lf.y - rng(0, lf.size*0.5),
                        vx: rng(-0.4, 0.4),
                        vy: rng(-2.4, -4.2),
                        life: 0, maxLife: rng(700, 1400),
                        size: rng(1, 2.2),
                        col: rngI(0, 3)  /* 0 yellow, 1 orange, 2 red */
                    });
                }
                if (Math.random() < 0.06 && lavaSmoke.length < 80) {
                    lavaSmoke.push({
                        x: lf.x + rng(-3, 3),
                        y: lf.y - lf.size*0.4,
                        vx: rng(-0.25, 0.25),
                        vy: rng(-0.5, -1.1),
                        r: rng(6, 12), maxR: rng(28, 56),
                        life: 0, maxLife: rng(2200, 4400)
                    });
                }
            }
            for (var i=lavaFires.length-1; i>=0; i--) {
                if (lavaFires[i].life > lavaFires[i].maxLife)
                    lavaFires.splice(i, 1);
            }
            for (var i=lavaEmbers.length-1; i>=0; i--) {
                var em = lavaEmbers[i];
                em.x += em.vx*k; em.y += em.vy*k;
                em.vy *= 0.985; em.life += dt;
                if (em.life > em.maxLife) lavaEmbers.splice(i, 1);
            }
            for (var i=lavaSmoke.length-1; i>=0; i--) {
                var sk = lavaSmoke[i];
                sk.x += sk.vx*k; sk.y += sk.vy*k;
                sk.r = Math.min(sk.maxR, sk.r + 0.035*k);
                sk.life += dt;
                if (sk.life > sk.maxLife) lavaSmoke.splice(i, 1);
            }
            for (var i=0; i<lavaCraters.length; i++) lavaCraters[i].born += dt;
        }

        else if (type === 'plasmaStorm') {
            plasmaTimer += dt;
            if (plasmaTimer > rng(140, 380)) {
                plasmaTimer = 0;
                /* strike an ACTUAL target — a building rooftop or a
                   moving car. Bolt zigzags from a random cloud point
                   down to the target. */
                var tgt = pickImpactTarget();
                var startX = tgt.x + rng(-W*0.12, W*0.12);
                var startY = rng(0, GROUND*0.35);
                var hitX = tgt.x, hitY = tgt.y;
                var segs = [{ x: startX, y: startY }];
                var sx = startX, sy = startY;
                while (sy < hitY - 60) {
                    sx += rng(-50, 50);
                    sy += rng(40, 90);
                    segs.push({ x: sx, y: sy });
                }
                segs.push({ x: hitX, y: hitY });
                var palette = ['#00ddff','#ff44ff','#ffee44','#44ffaa'];
                var col = palette[rngI(0, palette.length)];
                plasmaArcs.push({
                    segs: segs, life: 0, maxLife: rng(400, 900),
                    color: col,
                    width: rng(1.5, 3.5)
                });
                /* impact site — burning scorch + sparks + smoke */
                plasmaImpacts.push({
                    x: hitX, y: hitY,
                    r: 0, maxR: rng(14, 26),
                    life: 0, maxLife: rng(3000, 5500),
                    flicker: rng(0, Math.PI*2),
                    col: col
                });
                for (var ps=0; ps<24; ps++) plasmaSparks.push({
                    x: hitX, y: hitY,
                    vx: rng(-3, 3), vy: rng(-3, 0.5),
                    life: 0, maxLife: rng(400, 900),
                    col: col
                });
                plasmaSmoke.push({
                    x: hitX, y: hitY,
                    vy: rng(-0.4, -0.9), vx: rng(-0.2, 0.2),
                    r: rng(4, 8), maxR: rng(28, 50),
                    life: 0, maxLife: rng(2400, 4800)
                });
            }
            for (var i=plasmaArcs.length-1; i>=0; i--) {
                plasmaArcs[i].life += dt;
                if (plasmaArcs[i].life >= plasmaArcs[i].maxLife)
                    plasmaArcs.splice(i, 1);
            }
            for (var i=plasmaImpacts.length-1; i>=0; i--) {
                var im = plasmaImpacts[i];
                im.life += dt; im.flicker += 0.015*dt;
                im.r = Math.min(im.maxR, im.r + 0.06*k);
                if (im.life > im.maxLife) plasmaImpacts.splice(i, 1);
            }
            for (var i=plasmaSparks.length-1; i>=0; i--) {
                var sk = plasmaSparks[i];
                sk.x += sk.vx*k; sk.y += sk.vy*k;
                sk.vy += 0.18*k; sk.life += dt;
                if (sk.life > sk.maxLife) plasmaSparks.splice(i, 1);
            }
            for (var i=plasmaSmoke.length-1; i>=0; i--) {
                var ss = plasmaSmoke[i];
                ss.x += ss.vx*k; ss.y += ss.vy*k;
                ss.r = Math.min(ss.maxR, ss.r + 0.025*k);
                ss.life += dt;
                if (ss.life > ss.maxLife) plasmaSmoke.splice(i, 1);
            }
        }

        else if (type === 'cosmicRay') {
            for (var i=0; i<cosmicBeams.length; i++) {
                var cb = cosmicBeams[i];
                cb.pulse += cb.pulseRate*dt;
                /* every couple of seconds a beam VAPORIZES a building
                   at its base — spawn a glowing impact crater and a
                   column of disintegration particles rising upward. */
                cb._impactTimer = (cb._impactTimer || rng(1500, 3500)) - dt;
                if (cb._impactTimer <= 0) {
                    cb._impactTimer = rng(2000, 5000);
                    /* vaporize a real building / car at the beam line */
                    var tg = pickImpactTarget();
                    var ix = tg.x, iy = tg.y;
                    /* pick a spectral colour for this beam strike from
                       a multi-hue cosmic palette */
                    var cosmicCols = ['#a8e0ff','#ffb0ff','#aaffd0','#ffe070',
                                       '#b890ff','#80ffe0','#ffa080','#d0ffa0'];
                    var col = cosmicCols[rngI(0, cosmicCols.length)];
                    cosmicImpacts.push({
                        x: ix, y: iy,
                        r: 0, maxR: rng(18, 32),
                        life: 0, maxLife: rng(2200, 4400),
                        flash: 1,
                        col: col
                    });
                    /* burst of vaporization particles tinted to match */
                    for (var v=0; v<32; v++) cosmicVapor.push({
                        x: ix + rng(-10, 10),
                        y: iy + rng(-4, 4),
                        vx: rng(-0.5, 0.5),
                        vy: rng(-2.5, -5),
                        life: 0, maxLife: rng(900, 1800),
                        size: rng(1, 2.4),
                        col: col
                    });
                }
            }
            for (var i=0; i<cosmicSparks.length; i++) {
                var cs = cosmicSparks[i];
                cs.y += cs.vy*k; cs.life += dt;
                if (cs.y > GROUND || cs.life > cs.maxLife) {
                    cs.x = rng(0, W); cs.y = rng(0, H*0.2);
                    cs.life = 0; cs.maxLife = rng(500, 1400);
                }
            }
            for (var i=cosmicImpacts.length-1; i>=0; i--) {
                var ci = cosmicImpacts[i];
                ci.life += dt;
                ci.r = Math.min(ci.maxR, ci.r + 0.06*k);
                ci.flash = Math.max(0, ci.flash - 0.004*k);
                if (ci.life > ci.maxLife) cosmicImpacts.splice(i, 1);
            }
            for (var i=cosmicVapor.length-1; i>=0; i--) {
                var cv = cosmicVapor[i];
                cv.x += cv.vx*k; cv.y += cv.vy*k;
                cv.vy *= 0.985; cv.life += dt;
                if (cv.life > cv.maxLife) cosmicVapor.splice(i, 1);
            }
        }

        else if (type === 'quantumGlitch') {
            glitchTimer += dt;
            for (var i=0; i<glitchPixels.length; i++) {
                glitchPixels[i].next -= dt;
                if (glitchPixels[i].next <= 0) {
                    glitchPixels[i].x = rng(0, W);
                    glitchPixels[i].y = rng(0, GROUND);
                    glitchPixels[i].next = rng(40, 400);
                }
            }
            if (glitchTimer > rng(200, 700)) {
                glitchTimer = 0;
                glitchBars.push({
                    y: rng(0, GROUND),
                    h: rngI(2, 24),
                    shift: rngI(-30, 30),
                    life: 0, maxLife: rng(120, 320),
                    col: ['rgba(255,0,80,0.45)','rgba(0,255,180,0.45)','rgba(60,140,255,0.45)'][rngI(0,3)]
                });
            }
            for (var i=glitchBars.length-1; i>=0; i--) {
                glitchBars[i].life += dt;
                if (glitchBars[i].life >= glitchBars[i].maxLife)
                    glitchBars.splice(i, 1);
            }
        }
    }

    /* Ground-anchored layer of the active custom event — drawn
       BEFORE vehicles so cars sit on top of the puddles / craters /
       impact scorches. Per-user request:
         - acid rain corrosion pools must be UNDER cars
         - lava rain craters + splats must be UNDER cars */
    function drawCustomEventGround(c) {
        var type = effType(EVENTS[eventIndex]);

        /* ── acid rain ground layer: pools + their dark etch beneath ── */
        if (type === 'acidRain') {
            for (var i=0; i<acidPools.length; i++) {
                var po = acidPools[i];
                var p = po.life / po.maxLife;
                var op = (p < 0.85) ? 1 : (1 - p)/0.15;
                /* dark etch beneath pool */
                c.fillStyle = 'rgba(60,70,20,' + (op*0.55) + ')';
                c.beginPath();
                c.ellipse(po.x, po.y + 1, po.r*1.1, po.r*0.35, 0, 0, Math.PI*2);
                c.fill();
                /* fluorescent pool body */
                var pg = c.createRadialGradient(po.x, po.y, 0,
                                                 po.x, po.y, po.r);
                pg.addColorStop(0,   'rgba(220,255,120,' + (op*0.95) + ')');
                pg.addColorStop(0.6, 'rgba(160,210,40,' + (op*0.85) + ')');
                pg.addColorStop(1,   'rgba(80,120,20,0)');
                c.fillStyle = pg;
                c.beginPath();
                c.ellipse(po.x, po.y - 1, po.r, po.r*0.42, 0, 0, Math.PI*2);
                c.fill();
                /* bubble caps */
                for (var bb=0; bb<3; bb++) {
                    var ba = po.bubble + bb*2.1;
                    var bx = po.x + Math.cos(ba)*po.r*0.6;
                    var by = po.y - 2 + Math.sin(ba)*po.r*0.15;
                    var br = 1.5 + Math.sin(ba*1.7)*0.8 + 1;
                    c.fillStyle = 'rgba(250,255,180,' + (op*0.85) + ')';
                    c.beginPath(); c.arc(bx, by, br, 0, Math.PI*2); c.fill();
                    c.strokeStyle = 'rgba(120,160,40,' + (op*0.85) + ')';
                    c.lineWidth = 0.6;
                    c.stroke();
                }
            }
        }

        /* ── crystal storm ground layer: embedded "stuck" shards ──
           Lodged shards render here so cars (and any pedestrian
           layer) draw over them. The falling crystals continue to
           render above cars in drawCustomEvent — only the embedded
           damage shards are pushed below. */
        if (type === 'crystalStorm') {
            for (var i=0; i<stuckCrystals.length; i++) {
                var sk = stuckCrystals[i];
                c.fillStyle = 'rgba(20,30,50,0.55)';
                c.beginPath();
                c.ellipse(sk.x, sk.y + sk.r*0.4,
                          sk.r*0.9, sk.r*0.25, 0, 0, Math.PI*2);
                c.fill();
                c.save();
                c.translate(sk.x, sk.y);
                c.rotate(sk.angle);
                var sg = c.createLinearGradient(0, -sk.r, 0, sk.r);
                sg.addColorStop(0,   'rgba(220,240,255,0.95)');
                sg.addColorStop(0.5, 'rgba(150,200,240,0.95)');
                sg.addColorStop(1,   'rgba(70,110,160,0.95)');
                c.fillStyle = sg;
                c.beginPath();
                c.moveTo(0, -sk.r);
                c.lineTo(sk.r*0.6, 0);
                c.lineTo(0, sk.r);
                c.lineTo(-sk.r*0.6, 0);
                c.closePath();
                c.fill();
                c.strokeStyle = 'rgba(20,40,80,0.85)';
                c.lineWidth = 1;
                c.stroke();
                var tw = 0.5 + 0.5*Math.sin(sk.shine);
                c.fillStyle = 'rgba(255,255,255,' + tw + ')';
                c.beginPath();
                c.arc(0, -sk.r*0.3, sk.r*0.15, 0, Math.PI*2);
                c.fill();
                c.restore();
            }
        }

        /* ── lava rain ground layer: permanent craters + splats +
              ground fires (so cars drive on top of all of them) ── */
        if (type === 'lavaRain') {
            /* crater scars first (oldest at bottom of z) */
            for (var i=0; i<lavaCraters.length; i++) {
                var cr = lavaCraters[i];
                c.fillStyle = 'rgba(20,10,5,0.55)';
                c.beginPath();
                c.ellipse(cr.x, cr.y, cr.r, cr.r*0.4, 0, 0, Math.PI*2);
                c.fill();
                if (cr.born < 1500) {
                    var hot = 1 - cr.born/1500;
                    c.strokeStyle = 'rgba(255,120,30,' + (hot*0.55) + ')';
                    c.lineWidth = 1.4;
                    c.beginPath();
                    c.ellipse(cr.x, cr.y, cr.r, cr.r*0.4, 0, 0, Math.PI*2);
                    c.stroke();
                }
            }
            /* pulsing molten splats */
            for (var i=0; i<lavaSplats.length; i++) {
                var s = lavaSplats[i];
                var op = Math.max(0, 1 - s.life/s.maxLife);
                var g = c.createRadialGradient(s.x, s.y, 0, s.x, s.y, s.r);
                g.addColorStop(0, 'rgba(255,220,80,' + (op*1.00) + ')');
                g.addColorStop(0.55, 'rgba(255,120,30,' + (op*0.80) + ')');
                g.addColorStop(1, 'rgba(80,20,0,0)');
                c.fillStyle = g;
                c.fillRect(s.x-s.r, s.y-s.r, s.r*2, s.r*2);
            }
            /* ground-level fires (those NOT on buildings or cars) —
               drawn here so cars occlude them. Building-tied + car-tied
               fires render above cars in the main drawCustomEvent so
               they appear ON the structure they ignited. */
            for (var i=0; i<lavaFires.length; i++) {
                var lf = lavaFires[i];
                if (lf.onBuilding || lf.onCar) continue;
                drawLavaFire(c, lf);
            }
        }
    }

    /* Shared fire-petal renderer used by both ground and above-car
       passes for lavaRain. */
    function drawLavaFire(c, lf) {
        var fadeIn  = Math.min(1, lf.life/200);
        var fadeOut = Math.min(1, (lf.maxLife - lf.life)/800);
        var fop = fadeIn * fadeOut;
        var flick = 0.85 + 0.15*Math.sin(lf.flicker);
        var fs = lf.size * flick;
        /* halo */
        var fg = c.createRadialGradient(lf.x, lf.y, 0,
                                         lf.x, lf.y, fs*2.5);
        fg.addColorStop(0, 'rgba(255,220,80,' + (0.9*fop) + ')');
        fg.addColorStop(0.4, 'rgba(255,120,30,' + (0.6*fop) + ')');
        fg.addColorStop(1, 'rgba(120,30,0,0)');
        c.fillStyle = fg;
        c.fillRect(lf.x-fs*2.5, lf.y-fs*2.5, fs*5, fs*5);
        /* layered flame petals — 3 stacked teardrops */
        for (var pn=0; pn<3; pn++) {
            var ps = fs * (1 - pn*0.22);
            var py = lf.y - pn*ps*0.6 - ps*0.3;
            var col = ['rgba(255,80,20,'  + (fop*0.95) + ')',
                       'rgba(255,180,40,' + (fop*0.95) + ')',
                       'rgba(255,240,160,'+ (fop*0.95) + ')'][pn];
            c.fillStyle = col;
            c.beginPath();
            c.moveTo(lf.x, py - ps);
            c.bezierCurveTo(lf.x + ps*0.7, py - ps*0.4,
                            lf.x + ps*0.5, py + ps*0.5,
                            lf.x, py + ps*0.3);
            c.bezierCurveTo(lf.x - ps*0.5, py + ps*0.5,
                            lf.x - ps*0.7, py - ps*0.4,
                            lf.x, py - ps);
            c.fill();
        }
    }

    /* Render the active custom event onto the dynamic canvas. */
    function drawCustomEvent(c) {
        var type = effType(EVENTS[eventIndex]);

        /* ── TSUNAMI — full water-space scene ─────────────────────
           Stratified rendering, from back to front:
             1. Dark underwater body (gradient fill) below waterLevel.
             2. Rising bubbles inside that body.
             3. Three sine-displaced wave layers (back / mid / front)
                at different y, amplitude, period, and opacity.
             4. Floating debris bobbing on the surface phase.
             5. Foam crests popping along the front wave.
             6. Splash sparks where the surface meets obstacles. */
        if (type === 'tsunami' && tsunamiState) {
            var ts = tsunamiState;
            var wlBack = ts.waterLevel - 24;     /* back wave y reference */
            var wlMid  = ts.waterLevel - 8;
            var wlFront= ts.waterLevel + 6;

            /* 1. Deep water body */
            var bodyG = c.createLinearGradient(0, ts.waterLevel - 30, 0, H);
            bodyG.addColorStop(0,    'rgba(80,160,210,0.72)');
            bodyG.addColorStop(0.20, 'rgba(40,110,170,0.85)');
            bodyG.addColorStop(0.55, 'rgba(20,70,120,0.95)');
            bodyG.addColorStop(1,    'rgba(8,30,60,1)');
            c.fillStyle = bodyG;
            c.fillRect(0, ts.waterLevel - 30, W, H);

            /* 2. Bubbles in the dark water */
            for (var i=0; i<ts.bubbles.length; i++) {
                var bb = ts.bubbles[i];
                c.fillStyle = 'rgba(220,240,255,0.55)';
                c.beginPath(); c.arc(bb.x, bb.y, bb.r, 0, Math.PI*2); c.fill();
                c.strokeStyle = 'rgba(255,255,255,0.30)';
                c.lineWidth = 1;
                c.beginPath(); c.arc(bb.x - bb.r*0.35, bb.y - bb.r*0.35, bb.r*0.4, 0, Math.PI*2); c.stroke();
            }

            /* 3. Three wave layers — back, mid, front.
               Each is a poly-line of sine displacements filled down to H. */
            function drawWaveLayer(c, yRef, amp, period, phase, fillStyle) {
                c.fillStyle = fillStyle;
                c.beginPath();
                c.moveTo(0, H);
                var step = 8;
                for (var x=0; x<=W; x+=step) {
                    var y = yRef + Math.sin(x/period + phase)*amp
                                + Math.sin(x/(period*0.41) + phase*1.7)*amp*0.35;
                    c.lineTo(x, y);
                }
                c.lineTo(W, H);
                c.closePath();
                c.fill();
            }
            drawWaveLayer(c, wlBack,  10, 90,  ts.wavePhase3, 'rgba(80,140,200,0.55)');
            drawWaveLayer(c, wlMid,   16, 70,  ts.wavePhase2, 'rgba(50,110,180,0.75)');
            drawWaveLayer(c, wlFront, 24, 55,  ts.wavePhase1, 'rgba(30,80,150,0.92)');

            /* highlight along the front wave crest */
            c.strokeStyle = 'rgba(230,245,255,0.45)';
            c.lineWidth = 2;
            c.beginPath();
            for (var x=0; x<=W; x+=6) {
                var y = wlFront + Math.sin(x/55 + ts.wavePhase1)*24
                                + Math.sin(x/22.5 + ts.wavePhase1*1.7)*8;
                if (x===0) c.moveTo(x, y); else c.lineTo(x, y);
            }
            c.stroke();

            /* 4. Floating debris (planks) */
            for (var i=0; i<ts.debris.length; i++) {
                var dz = ts.debris[i];
                var surfY = wlFront + Math.sin(dz.x/55 + ts.wavePhase1)*24
                                    + Math.sin(dz.phase)*3;
                c.save();
                c.translate(dz.x, surfY);
                c.rotate(dz.rot + Math.sin(dz.phase)*0.15);
                c.fillStyle = '#6e4c2a';
                c.fillRect(-dz.w/2, -dz.h/2, dz.w, dz.h);
                c.strokeStyle = '#3a2614';
                c.lineWidth = 1;
                c.strokeRect(-dz.w/2, -dz.h/2, dz.w, dz.h);
                /* plank grain */
                c.strokeStyle = 'rgba(60,40,20,0.55)';
                c.beginPath();
                c.moveTo(-dz.w/2 + 4, -dz.h/2 + 2);
                c.lineTo( dz.w/2 - 4, -dz.h/2 + 2);
                c.moveTo(-dz.w/2 + 4,  dz.h/2 - 2);
                c.lineTo( dz.w/2 - 4,  dz.h/2 - 2);
                c.stroke();
                c.restore();
            }

            /* 5. Foam crests — small white blobs riding the front wave */
            for (var i=0; i<ts.foamCrests.length; i++) {
                var f = ts.foamCrests[i];
                var op = (1 - f.life/f.maxLife) * 0.85;
                c.fillStyle = 'rgba(240,250,255,' + op + ')';
                c.beginPath(); c.arc(f.x, f.y, f.r, 0, Math.PI*2); c.fill();
            }

            /* 6. Splash sparks (small droplets popping off the surface) */
            for (var i=0; i<ts.splashSparks.length; i++) {
                var sk = ts.splashSparks[i];
                var op = (1 - sk.life/sk.maxLife);
                c.fillStyle = 'rgba(200,230,255,' + op + ')';
                c.beginPath(); c.arc(sk.x, sk.y, 1.5, 0, Math.PI*2); c.fill();
            }
        }

        /* ── MIRROR RAIN ─────────────────────────────────────────
           Falling mirror shards (rotating thin rectangles with a
           white catch-light flash) and drifting prismatic specks
           (small HSL-rotating dots) below them. */
        else if (type === 'mirrorRain') {
            /* drifting rainbow specks (background) */
            for (var i=0; i<mirrorPrisms.length; i++) {
                var pr = mirrorPrisms[i];
                var p = pr.life / pr.maxLife;
                var op = (p < 0.5 ? p*2 : (1-p)*2) * 0.85;
                c.fillStyle = 'hsla(' + pr.hue + ', 90%, 70%, ' + op + ')';
                c.beginPath();
                c.arc(pr.x, pr.y, pr.size, 0, Math.PI*2);
                c.fill();
            }
            /* mirror shards (foreground) */
            for (var i=0; i<mirrorShards.length; i++) {
                var ms = mirrorShards[i];
                c.save();
                c.translate(ms.x, ms.y);
                c.rotate(ms.angle);
                /* shard body — dark glass with a bright vertical highlight */
                var g = c.createLinearGradient(-ms.w/2, 0, ms.w/2, 0);
                g.addColorStop(0,   'rgba(60,75,95,0.85)');
                g.addColorStop(0.4, 'rgba(140,170,200,0.95)');
                g.addColorStop(0.55,'rgba(245,250,255,1)');
                g.addColorStop(0.7, 'rgba(170,195,220,0.90)');
                g.addColorStop(1,   'rgba(50,65,85,0.85)');
                c.fillStyle = g;
                c.fillRect(-ms.w/2, -ms.h/2, ms.w, ms.h);
                /* rim outline */
                c.strokeStyle = 'rgba(20,30,40,0.75)';
                c.lineWidth = 0.8;
                c.strokeRect(-ms.w/2, -ms.h/2, ms.w, ms.h);
                /* shimmer streak — a moving bright bar */
                var streakY = -ms.h/2 + ((Math.sin(ms.shimmer)*0.5 + 0.5) * ms.h);
                c.fillStyle = 'rgba(255,255,255,0.85)';
                c.fillRect(-ms.w/2 + 0.5, streakY, ms.w - 1, 1.5);
                c.restore();
            }
        }

        /* ── SULFURIC ACID RAIN ──────────────────────────────────
           City colour stays untouched. Layers (back → front):
             1. Acid drops streaking down through the air
             2. Drips of melting paint running down imaginary
                building edges (mid-air vertical streaks)
             3. Steam wisps rising off the corrosion
             4. Sizzling ground splats (rings) + a fizz droplet
             5. Persistent corrosion pools at street level (bubbling
                yellow-green puddles with bubble caps)
             6. Charred etch-pits beneath the pools */
        else if (type === 'acidRain') {
            /* 1. drops */
            c.strokeStyle = 'rgba(180,220,60,0.85)';
            c.lineWidth = 1.6;
            for (var i=0; i<acidDrops.length; i++) {
                var a = acidDrops[i];
                c.beginPath();
                c.moveTo(a.x, a.y);
                c.lineTo(a.x - a.vx*1.5, a.y - a.len);
                c.stroke();
            }

            /* 2. melting paint drips on buildings + cars (vertical
                  streaks in melt-colour with a bulbous head). */
            for (var i=0; i<acidDripFalls.length; i++) {
                var dr = acidDripFalls[i];
                /* streak */
                var grad = c.createLinearGradient(dr.x, dr.y - dr.len,
                                                   dr.x, dr.y);
                grad.addColorStop(0, dr.col + '0)');
                grad.addColorStop(1, dr.col + '0.92)');
                c.fillStyle = grad;
                c.fillRect(dr.x - 1.4, dr.y - dr.len, 2.8, dr.len);
                /* bulb at the leading tip — about to detach */
                c.fillStyle = dr.col + '1)';
                c.beginPath();
                c.arc(dr.x, dr.y, 2.2, 0, Math.PI*2);
                c.fill();
            }

            /* 3. steam wisps */
            for (var i=0; i<acidSteam.length; i++) {
                var st = acidSteam[i];
                var op = (1 - st.life/st.maxLife) * 0.45;
                var sg = c.createRadialGradient(st.x, st.y, 0, st.x, st.y, st.r);
                sg.addColorStop(0, 'rgba(220,250,180,' + op + ')');
                sg.addColorStop(1, 'rgba(220,250,180,0)');
                c.fillStyle = sg;
                c.fillRect(st.x - st.r, st.y - st.r, st.r*2, st.r*2);
            }

            /* 4. sizzling splats — fizz ring + droplet halo */
            for (var i=0; i<acidSplats.length; i++) {
                var s = acidSplats[i];
                var op = 1 - s.life/s.maxLife;
                c.strokeStyle = 'rgba(200,255,80,' + (op*0.85) + ')';
                c.lineWidth = 1.5;
                c.beginPath(); c.arc(s.x, s.y, s.r, 0, Math.PI*2); c.stroke();
                if (s.r > 4) {
                    c.fillStyle = 'rgba(220,255,160,' + (op*0.45) + ')';
                    c.beginPath(); c.arc(s.x, s.y, s.r*0.4, 0, Math.PI*2); c.fill();
                }
                c.fillStyle = 'rgba(230,255,140,' + (op*0.30) + ')';
                c.beginPath(); c.arc(s.x + Math.sin(s.life*0.02)*3,
                                     s.y - s.r*0.6, 1.2, 0, Math.PI*2);
                c.fill();
            }

            /* corrosion pools render via drawCustomEventGround() so
               they sit underneath the vehicles (cars drive over the
               puddle, not under it visually). Nothing to draw here. */
        }

        /* ── GRAVITY WELL ─────────────────────────────────────────
           Layered render (back → front):
             1. Outer space-distortion rings (concentric, faded)
             2. Expanding shockwave rings (periodic)
             3. Tractor-beam light cones (from buildings → well)
             4. Building-debris streams curving along bezier paths
                from each beam target into the singularity
             5. Multi-ring accretion disc (3 rotated arcs)
             6. Spiralling cosmic debris
             7. Event horizon (black core + violet halo)
             8. Gravitational-lens highlight crescent */
        else if (type === 'gravityWell' && gravityState) {
            var gs = gravityState;

            /* 1. faint outer distortion rings */
            for (var or=0; or<5; or++) {
                var ro = gs.r + 80 + or*28;
                c.strokeStyle = 'rgba(150,100,200,' + (0.08 - or*0.013) + ')';
                c.lineWidth = 1;
                c.beginPath();
                c.arc(gs.cx, gs.cy, ro, 0, Math.PI*2);
                c.stroke();
            }

            /* 2. expanding shockwave rings */
            for (var i=0; i<gravityRings.length; i++) {
                var gr = gravityRings[i];
                var op = (1 - gr.life/gr.maxLife) * gr.strength * 0.6;
                c.strokeStyle = 'rgba(200,160,255,' + op + ')';
                c.lineWidth = 2.5;
                c.beginPath();
                c.arc(gs.cx, gs.cy, gr.r, 0, Math.PI*2);
                c.stroke();
            }

            /* 3. tractor-beam light cones */
            for (var b=0; b<gravityBeams.length; b++) {
                var gb = gravityBeams[b];
                var pulse = 0.5 + 0.5*Math.sin(gb.pulse);
                var bg = c.createLinearGradient(gb.bx, gb.by, gs.cx, gs.cy);
                bg.addColorStop(0, 'rgba(190,140,255,' + (0.35*pulse) + ')');
                bg.addColorStop(1, 'rgba(190,140,255,0)');
                c.strokeStyle = bg;
                c.lineWidth = 6 * pulse;
                c.beginPath();
                c.moveTo(gb.bx, gb.by);
                c.lineTo(gs.cx, gs.cy);
                c.stroke();
                /* a softer wider halo around the beam */
                c.strokeStyle = 'rgba(180,120,250,' + (0.15*pulse) + ')';
                c.lineWidth = 16 * pulse;
                c.stroke();
                /* glow pin at the building end */
                var bg2 = c.createRadialGradient(gb.bx, gb.by, 0,
                                                 gb.bx, gb.by, 14);
                bg2.addColorStop(0, 'rgba(255,220,255,' + (0.85*pulse) + ')');
                bg2.addColorStop(1, 'rgba(180,120,255,0)');
                c.fillStyle = bg2;
                c.fillRect(gb.bx-14, gb.by-14, 28, 28);
            }

            /* 4. flying building debris (planks, slabs) */
            for (var i=0; i<gravityDebris.length; i++) {
                var bd = gravityDebris[i];
                /* curved bezier from start (bx,by) toward (cx,cy) with
                   a slight upward control point so it arcs */
                var t = bd.progress;
                var ctlX = (bd.x + bd.targetX)/2;
                var ctlY = Math.min(bd.y, bd.targetY) - 80;
                var mt = 1 - t;
                var px = mt*mt*bd.x + 2*mt*t*ctlX + t*t*bd.targetX;
                var py = mt*mt*bd.y + 2*mt*t*ctlY + t*t*bd.targetY;
                /* spaghettified shrink near the well */
                var shrink = 1 - t*0.75;
                var cols = ['rgba(140,140,150,0.92)',
                            'rgba(150,110,80,0.92)',
                            'rgba(190,170,140,0.92)'];
                c.save();
                c.translate(px, py);
                c.rotate(bd.rot);
                c.fillStyle = cols[bd.col];
                c.fillRect(-bd.size*shrink, -bd.size*0.6*shrink,
                            bd.size*2*shrink, bd.size*1.2*shrink);
                c.strokeStyle = 'rgba(20,20,30,0.65)';
                c.lineWidth = 0.6;
                c.strokeRect(-bd.size*shrink, -bd.size*0.6*shrink,
                              bd.size*2*shrink, bd.size*1.2*shrink);
                c.restore();
            }

            /* 5. accretion disc — 3 rotated arcs */
            for (var ringI=0; ringI<3; ringI++) {
                var rr = gs.r + 30 + ringI*22;
                c.strokeStyle = 'rgba(180,120,255,' + (0.35 - ringI*0.08) + ')';
                c.lineWidth = 2 + ringI*1.5;
                c.beginPath();
                c.arc(gs.cx, gs.cy, rr,
                       gs.t*0.001 + ringI,
                       gs.t*0.001 + ringI + Math.PI*1.4);
                c.stroke();
            }

            /* 6. cosmic-debris speck cloud */
            for (var i=0; i<gs.debris.length; i++) {
                var d = gs.debris[i];
                var px = gs.cx + Math.cos(d.angle)*d.radius;
                var py = gs.cy + Math.sin(d.angle)*d.radius*0.35;
                var cols2 = ['rgba(255,255,255,0.92)',
                             'rgba(200,140,255,0.92)',
                             'rgba(255,180,80,0.92)'];
                c.fillStyle = cols2[d.hue];
                c.beginPath(); c.arc(px, py, d.size, 0, Math.PI*2); c.fill();
            }

            /* 7. event horizon — deep black with violet halo */
            var coreG = c.createRadialGradient(gs.cx, gs.cy, 0,
                                                gs.cx, gs.cy, gs.r);
            coreG.addColorStop(0,   'rgba(0,0,0,1)');
            coreG.addColorStop(0.70,'rgba(20,0,40,0.98)');
            coreG.addColorStop(0.90,'rgba(120,40,200,0.65)');
            coreG.addColorStop(1,   'rgba(160,80,255,0)');
            c.fillStyle = coreG;
            c.beginPath(); c.arc(gs.cx, gs.cy, gs.r, 0, Math.PI*2); c.fill();

            /* 8. lensing crescent — bright thin arc on the top edge */
            c.strokeStyle = 'rgba(255,220,255,0.55)';
            c.lineWidth = 1.5;
            c.beginPath();
            c.arc(gs.cx, gs.cy, gs.r + 2,
                   Math.PI*1.15, Math.PI*1.85);
            c.stroke();
        }

        /* ── CRYSTAL STORM ────────────────────────────────────── */
        else if (type === 'crystalStorm') {
            /* glitter sparkles in the air */
            for (var i=0; i<crystalGlitter.length; i++) {
                var gl = crystalGlitter[i];
                var p = gl.life/gl.maxLife;
                var op = (p < 0.5 ? p*2 : (1-p)*2) * 0.9;
                c.fillStyle = 'rgba(220,250,255,' + op + ')';
                c.fillRect(gl.x, gl.y, 1, 1);
                c.fillRect(gl.x-1, gl.y, 1, 1);
                c.fillRect(gl.x+1, gl.y, 1, 1);
                c.fillRect(gl.x, gl.y-1, 1, 1);
                c.fillRect(gl.x, gl.y+1, 1, 1);
            }
            /* embedded "stuck" crystals render in drawCustomEventGround()
               so cars draw over them — they're damage marks lodged in
               the road / car body / lower walls. Falling crystals
               continue above cars below. */

            /* falling crystals — small rotated diamonds with rim glow */
            for (var i=0; i<crystals.length; i++) {
                var cz = crystals[i];
                c.save();
                c.translate(cz.x, cz.y);
                c.rotate(cz.angle);
                c.fillStyle = 'rgba(180,230,255,0.85)';
                c.beginPath();
                c.moveTo(0, -cz.r);
                c.lineTo(cz.r*0.6, 0);
                c.lineTo(0, cz.r);
                c.lineTo(-cz.r*0.6, 0);
                c.closePath();
                c.fill();
                /* shine highlight */
                c.strokeStyle = 'rgba(255,255,255,' +
                                 (0.5 + 0.5*Math.sin(cz.shine)) + ')';
                c.lineWidth = 1;
                c.stroke();
                c.restore();
            }
        }

        /* ── LOCUST SWARM ─────────────────────────────────────────
           Each locust is a fully-detailed insect: segmented abdomen,
           thorax, head with two compound eyes, two antennae, two
           flapping fore-wings and two static hind-wings, six legs
           (three per side), and a faint motion-blur dust trail. */
        else if (type === 'locustSwarm') {
            /* dust haze backing */
            c.fillStyle = 'rgba(110,90,40,0.12)';
            c.fillRect(0, GROUND*0.2, W, GROUND*0.6);

            for (var i=0; i<locusts.length; i++) {
                var lc = locusts[i];
                var s  = lc.size;          /* base size */
                var x  = lc.x;
                var y  = lc.y;
                /* wing flap phase 0..1 then 1..0 — symmetric flap */
                var fl = Math.abs(Math.sin(lc.wing));

                /* motion-blur tail — faint trail behind */
                c.fillStyle = 'rgba(60,45,20,0.10)';
                c.beginPath();
                c.ellipse(x - s*3, y, s*1.6, s*0.4, 0, 0, Math.PI*2);
                c.fill();

                /* HIND WINGS (translucent, fanned out) — drawn first
                   so the fore-wings overlap them on top */
                c.fillStyle = 'rgba(180,160,110,0.45)';
                c.beginPath();
                c.ellipse(x - s*0.3, y - s*0.7, s*1.9, s*0.55 + s*0.4*fl,
                          -0.35, 0, Math.PI*2);
                c.fill();
                c.beginPath();
                c.ellipse(x - s*0.3, y - s*0.7, s*1.9, s*0.55 + s*0.4*fl,
                           0.35, 0, Math.PI*2);   /* mirror */
                c.fill();

                /* SEGMENTED ABDOMEN — 4 stacked tapering ellipses */
                for (var seg=0; seg<4; seg++) {
                    var segX = x - seg*s*0.55;
                    var segR = s*0.55 - seg*s*0.07;
                    c.fillStyle = (seg%2) ? 'rgba(70,55,25,0.95)'
                                          : 'rgba(95,75,35,0.95)';
                    c.beginPath();
                    c.ellipse(segX, y, segR, s*0.45, 0, 0, Math.PI*2);
                    c.fill();
                }

                /* THORAX */
                c.fillStyle = 'rgba(50,40,20,1)';
                c.beginPath();
                c.ellipse(x + s*0.55, y, s*0.7, s*0.55, 0, 0, Math.PI*2);
                c.fill();

                /* LEGS — three per side, springy zigzag */
                c.strokeStyle = 'rgba(30,22,12,0.95)';
                c.lineWidth = 0.8;
                for (var lg=0; lg<3; lg++) {
                    var lx = x - s*0.4 + lg*s*0.45;
                    /* below side */
                    c.beginPath();
                    c.moveTo(lx, y + s*0.25);
                    c.lineTo(lx - s*0.4, y + s*0.8);
                    c.lineTo(lx - s*0.15, y + s*1.4);
                    c.stroke();
                    /* above side (less visible) */
                    c.beginPath();
                    c.moveTo(lx, y - s*0.25);
                    c.lineTo(lx - s*0.3, y - s*0.55);
                    c.stroke();
                }
                /* hind-leg spike (locusts have a big jumping leg) */
                c.lineWidth = 1.4;
                c.beginPath();
                c.moveTo(x - s*0.4, y + s*0.25);
                c.lineTo(x - s*1.1, y - s*0.2);
                c.lineTo(x - s*1.5, y + s*1.0);
                c.stroke();

                /* FORE-WINGS (over the body, flapping) */
                c.fillStyle = 'rgba(120,95,50,0.85)';
                var wAmp = 0.7 + 0.6*fl;
                c.beginPath();
                c.ellipse(x + s*0.1, y - s*0.5*wAmp,
                          s*1.7, s*0.45*wAmp, -0.25, 0, Math.PI*2);
                c.fill();
                c.beginPath();
                c.ellipse(x + s*0.1, y - s*0.5*wAmp,
                          s*1.7, s*0.45*wAmp,  0.25, 0, Math.PI*2);
                c.fill();
                /* wing vein */
                c.strokeStyle = 'rgba(40,30,12,0.7)';
                c.lineWidth = 0.5;
                c.beginPath();
                c.moveTo(x - s*1.2, y - s*0.4*wAmp);
                c.lineTo(x + s*1.4, y - s*0.5*wAmp);
                c.stroke();

                /* HEAD */
                c.fillStyle = 'rgba(80,60,28,1)';
                c.beginPath();
                c.ellipse(x + s*1.2, y - s*0.05, s*0.55, s*0.5, 0, 0, Math.PI*2);
                c.fill();

                /* EYES — two compound eyes */
                c.fillStyle = '#ff7728';
                c.beginPath();
                c.arc(x + s*1.45, y - s*0.15, s*0.20, 0, Math.PI*2);
                c.fill();
                c.fillStyle = 'rgba(0,0,0,0.85)';
                c.beginPath();
                c.arc(x + s*1.50, y - s*0.18, s*0.10, 0, Math.PI*2);
                c.fill();
                /* tiny eye highlight */
                c.fillStyle = 'rgba(255,255,255,0.9)';
                c.beginPath();
                c.arc(x + s*1.52, y - s*0.22, s*0.04, 0, Math.PI*2);
                c.fill();

                /* ANTENNAE — two curving lines forward */
                c.strokeStyle = 'rgba(30,22,12,0.95)';
                c.lineWidth = 0.7;
                c.beginPath();
                c.moveTo(x + s*1.5, y - s*0.35);
                c.quadraticCurveTo(x + s*2.1, y - s*0.9, x + s*2.4, y - s*1.3);
                c.stroke();
                c.beginPath();
                c.moveTo(x + s*1.5, y - s*0.25);
                c.quadraticCurveTo(x + s*2.3, y - s*0.55, x + s*2.7, y - s*0.7);
                c.stroke();
            }
        }

        /* ── LAVA RAIN ────────────────────────────────────────────
           Layered render (back → front):
             1. Hellish ground glow strip
             2. Smoke plumes (drawn early so fires draw on top)
             3. Permanent ground crater scars
             4. Smoldering ground splats
             5. Lava drop trails
             6. Lava drop cores
             7. Active fires (on ground + on buildings)
             8. Rising embers */
        else if (type === 'lavaRain') {
            /* 1. ground glow */
            c.fillStyle = 'rgba(180,40,0,0.10)';
            c.fillRect(0, GROUND - 8, W, H - GROUND);

            /* 2. smoke plumes (greyish-orange) */
            for (var i=0; i<lavaSmoke.length; i++) {
                var sm = lavaSmoke[i];
                var op = (1 - sm.life/sm.maxLife) * 0.55;
                var sg = c.createRadialGradient(sm.x, sm.y, 0, sm.x, sm.y, sm.r);
                sg.addColorStop(0, 'rgba(120,80,40,' + (op*0.6) + ')');
                sg.addColorStop(0.6, 'rgba(80,55,30,' + (op*0.35) + ')');
                sg.addColorStop(1, 'rgba(40,28,18,0)');
                c.fillStyle = sg;
                c.fillRect(sm.x-sm.r, sm.y-sm.r, sm.r*2, sm.r*2);
            }

            /* lava craters + splats render via drawCustomEventGround()
               so cars drive across them rather than over them — see
               the ground-layer helper above. */

            /* 5. drop trails (warm glow segments) */
            for (var i=0; i<lavaDrops.length; i++) {
                var lv = lavaDrops[i];
                for (var t=lv.trail.length-1; t>=0; t--) {
                    var tr = lv.trail[t];
                    var fade = 1 - t/lv.trail.length;
                    c.fillStyle = 'rgba(255,140,40,' + (fade*0.45) + ')';
                    c.beginPath();
                    c.arc(tr.x, tr.y, lv.r*(0.4 + fade*0.6), 0, Math.PI*2);
                    c.fill();
                }
            }

            /* 6. lava drop cores */
            for (var i=0; i<lavaDrops.length; i++) {
                var lv = lavaDrops[i];
                var g = c.createRadialGradient(lv.x, lv.y, 0, lv.x, lv.y, lv.r*2);
                g.addColorStop(0, 'rgba(255,240,180,1)');
                g.addColorStop(0.4, 'rgba(255,150,40,0.95)');
                g.addColorStop(1, 'rgba(160,30,0,0)');
                c.fillStyle = g;
                c.fillRect(lv.x-lv.r*2, lv.y-lv.r*2, lv.r*4, lv.r*4);
            }

            /* 7. building-tied + car-tied fires only — these render
               ABOVE the cars so the flame stays attached to the
               structure it ignited. Ground fires render in
               drawCustomEventGround below cars (cars drive past them). */
            for (var i=0; i<lavaFires.length; i++) {
                var lf = lavaFires[i];
                if (!(lf.onBuilding || lf.onCar)) continue;
                drawLavaFire(c, lf);
            }

            /* 8. rising embers — yellow→orange→red specks */
            var embCols = ['rgba(255,240,140,',
                           'rgba(255,170,60,',
                           'rgba(255,90,30,'];
            for (var i=0; i<lavaEmbers.length; i++) {
                var em = lavaEmbers[i];
                var op = (1 - em.life/em.maxLife) * 0.95;
                c.fillStyle = embCols[em.col] + op + ')';
                c.beginPath();
                c.arc(em.x, em.y, em.size, 0, Math.PI*2);
                c.fill();
            }
        }

        /* ── PLASMA STORM ─────────────────────────────────────────
           Layered render:
             1. Smoke columns from electrocuted strike sites (back)
             2. Burning scorch impacts at building rooftops
             3. Arcing plasma bolts (outer glow + bright core)
             4. Spark showers radiating from impacts */
        else if (type === 'plasmaStorm') {
            /* 1. plasma smoke plumes */
            for (var i=0; i<plasmaSmoke.length; i++) {
                var ps = plasmaSmoke[i];
                var op = (1 - ps.life/ps.maxLife) * 0.55;
                var psg = c.createRadialGradient(ps.x, ps.y, 0, ps.x, ps.y, ps.r);
                psg.addColorStop(0, 'rgba(110,90,140,' + (op*0.65) + ')');
                psg.addColorStop(1, 'rgba(40,30,60,0)');
                c.fillStyle = psg;
                c.fillRect(ps.x-ps.r, ps.y-ps.r, ps.r*2, ps.r*2);
            }

            /* parse `#rrggbb` into rgba(r,g,b,a). Local helper. */
            function hexA(hex, a) {
                var h = hex.replace('#', '');
                var r = parseInt(h.substr(0, 2), 16),
                    g = parseInt(h.substr(2, 2), 16),
                    b = parseInt(h.substr(4, 2), 16);
                return 'rgba(' + r + ',' + g + ',' + b + ',' + a + ')';
            }
            /* 2. impact scorch — bright halo + dark crater */
            for (var i=0; i<plasmaImpacts.length; i++) {
                var im = plasmaImpacts[i];
                var fadeIn = Math.min(1, im.life/200);
                var fadeOut = Math.min(1, (im.maxLife - im.life)/600);
                var iop = fadeIn * fadeOut;
                var flick = 0.7 + 0.3*Math.sin(im.flicker);
                /* glowing halo in the strike colour */
                var ig2 = c.createRadialGradient(im.x, im.y, 0,
                                                  im.x, im.y, im.r*1.8);
                ig2.addColorStop(0,   hexA(im.col, 0.85*iop*flick));
                ig2.addColorStop(0.5, hexA(im.col, 0.45*iop*flick));
                ig2.addColorStop(1,   hexA(im.col, 0));
                c.fillStyle = ig2;
                c.fillRect(im.x-im.r*1.8, im.y-im.r*1.8, im.r*3.6, im.r*3.6);
                /* dark scorch core */
                c.fillStyle = 'rgba(20,10,30,' + (iop*0.75) + ')';
                c.beginPath();
                c.arc(im.x, im.y, im.r*0.55, 0, Math.PI*2);
                c.fill();
                /* electric crackle ring */
                c.strokeStyle = hexA(im.col, iop*flick);
                c.lineWidth = 1.5;
                c.beginPath();
                c.arc(im.x, im.y, im.r*0.9, 0, Math.PI*2);
                c.stroke();
            }

            /* 3. arcing bolts — outer glow + bright core */
            for (var i=0; i<plasmaArcs.length; i++) {
                var arc = plasmaArcs[i];
                var p = arc.life/arc.maxLife;
                var op = Math.sin(Math.min(1, p)*Math.PI);
                c.strokeStyle = arc.color;
                c.globalAlpha = op * 0.35;
                c.lineWidth = arc.width * 3.5;
                c.beginPath();
                c.moveTo(arc.segs[0].x, arc.segs[0].y);
                for (var s=1; s<arc.segs.length; s++) c.lineTo(arc.segs[s].x, arc.segs[s].y);
                c.stroke();
                c.strokeStyle = 'rgba(255,255,255,' + op + ')';
                c.lineWidth = arc.width;
                c.beginPath();
                c.moveTo(arc.segs[0].x, arc.segs[0].y);
                for (var s=1; s<arc.segs.length; s++) c.lineTo(arc.segs[s].x, arc.segs[s].y);
                c.stroke();
                c.globalAlpha = 1;
            }

            /* 4. spark showers from impacts */
            for (var i=0; i<plasmaSparks.length; i++) {
                var sk = plasmaSparks[i];
                var op = (1 - sk.life/sk.maxLife);
                c.fillStyle = sk.col;
                c.globalAlpha = op;
                c.fillRect(sk.x - 1, sk.y - 1, 2, 2);
                c.globalAlpha = 1;
            }
        }

        /* ── COSMIC RAY ───────────────────────────────────────────
           Layered render:
             1. Vertical pulsing light beams from above
             2. Shimmering particle streams falling
             3. Impact craters at beam strike sites — bright flash
                fading into a glowing crater scar
             4. Disintegration particles rising from impact sites */
        else if (type === 'cosmicRay') {
            /* 1. vertical beams — each beam tinted with its own
               cosmic colour from the multi-hue palette. */
            for (var i=0; i<cosmicBeams.length; i++) {
                var b = cosmicBeams[i];
                var alpha = b.alpha * (0.65 + 0.35*Math.sin(b.pulse));
                /* parse 'rgb(r,g,b)' → numeric parts */
                var bp = b.col.match(/\d+/g);
                var br = bp[0], bg_ = bp[1], bb = bp[2];
                var g = c.createLinearGradient(0, 0, 0, GROUND);
                g.addColorStop(0,
                    'rgba(' + br + ',' + bg_ + ',' + bb + ',' + alpha + ')');
                g.addColorStop(0.6,
                    'rgba(' + br + ',' + bg_ + ',' + bb + ',' + (alpha*0.5) + ')');
                g.addColorStop(1,
                    'rgba(' + br + ',' + bg_ + ',' + bb + ',0)');
                c.fillStyle = g;
                c.fillRect(b.x - b.w/2, 0, b.w, GROUND);
            }
            /* 2. shimmering particle streams — each spark tinted */
            for (var i=0; i<cosmicSparks.length; i++) {
                var sp = cosmicSparks[i];
                var p = sp.life/sp.maxLife;
                var op = (p < 0.5 ? p*2 : (1-p)*2);
                if (sp.col) {
                    var sps = sp.col.match(/\d+/g);
                    c.fillStyle = 'rgba(' + sps[0] + ',' + sps[1] +
                                  ',' + sps[2] + ',' + op + ')';
                } else {
                    c.fillStyle = 'rgba(220,240,255,' + op + ')';
                }
                c.beginPath(); c.arc(sp.x, sp.y, 1.5, 0, Math.PI*2); c.fill();
            }
            /* 3. impact craters — flash + scar tinted with strike colour */
            function hexAcr(hex, a) {
                var h = hex.replace('#', '');
                return 'rgba(' + parseInt(h.substr(0,2),16) +
                       ',' + parseInt(h.substr(2,2),16) +
                       ',' + parseInt(h.substr(4,2),16) + ',' + a + ')';
            }
            for (var i=0; i<cosmicImpacts.length; i++) {
                var ci = cosmicImpacts[i];
                var fadeIn = Math.min(1, ci.life/120);
                var fadeOut = Math.min(1, (ci.maxLife - ci.life)/700);
                var iop = fadeIn * fadeOut;
                var tintHex = ci.col || '#b8dcff';
                /* halo glow */
                var ig = c.createRadialGradient(ci.x, ci.y, 0,
                                                 ci.x, ci.y, ci.r*2.5);
                ig.addColorStop(0,   'rgba(255,255,255,' + (0.9*iop*ci.flash) + ')');
                ig.addColorStop(0.3, hexAcr(tintHex, 0.7*iop));
                ig.addColorStop(0.7, hexAcr(tintHex, 0.4*iop));
                ig.addColorStop(1,   hexAcr(tintHex, 0));
                c.fillStyle = ig;
                c.fillRect(ci.x-ci.r*2.5, ci.y-ci.r*2.5, ci.r*5, ci.r*5);
                /* crater rim — dark ring */
                c.strokeStyle = 'rgba(40,30,60,' + (iop*0.85) + ')';
                c.lineWidth = 2;
                c.beginPath();
                c.arc(ci.x, ci.y, ci.r, 0, Math.PI*2);
                c.stroke();
                /* charred core */
                c.fillStyle = 'rgba(10,5,20,' + (iop*0.65) + ')';
                c.beginPath();
                c.arc(ci.x, ci.y, ci.r*0.55, 0, Math.PI*2);
                c.fill();
                /* bright flash on first frame */
                if (ci.flash > 0.1) {
                    c.fillStyle = 'rgba(255,255,255,' + (ci.flash*iop) + ')';
                    c.beginPath();
                    c.arc(ci.x, ci.y, ci.r*0.35, 0, Math.PI*2);
                    c.fill();
                }
            }
            /* 4. vapor — particles tinted with their strike colour */
            for (var i=0; i<cosmicVapor.length; i++) {
                var cv = cosmicVapor[i];
                var op = (1 - cv.life/cv.maxLife);
                if (cv.col) {
                    c.fillStyle = hexAcr(cv.col, op);
                } else {
                    c.fillStyle = 'rgba(220,235,255,' + op + ')';
                }
                c.beginPath();
                c.arc(cv.x, cv.y, cv.size, 0, Math.PI*2);
                c.fill();
            }
        }

        /* ── QUANTUM GLITCH ───────────────────────────────────── */
        else if (type === 'quantumGlitch') {
            /* horizontal RGB-shifted bars */
            for (var i=0; i<glitchBars.length; i++) {
                var gb = glitchBars[i];
                var p = gb.life/gb.maxLife;
                var op = Math.sin(p*Math.PI);
                c.fillStyle = gb.col.replace('0.45', (op*0.45).toFixed(2));
                c.fillRect(0, gb.y, W, gb.h);
            }
            /* scattered RGB pixels */
            for (var i=0; i<glitchPixels.length; i++) {
                var gp = glitchPixels[i];
                c.fillStyle = gp.col;
                c.fillRect(gp.x, gp.y, gp.size, gp.size);
            }
            /* one big sweep scanline */
            var scanY = ((glitchTimer*0.4) % GROUND);
            c.fillStyle = 'rgba(255,255,255,0.05)';
            c.fillRect(0, scanY, W, 2);
        }
    }

    function initEvent(type) {
        particles=[]; splashes=[];
        floodY=GROUND; floodRising=(type==='flood');
        tSwayT=0; tX=W*0.5;
        ltTimer=0; ltActive=false; ltFlash=0; ltPts=[];
        eqShakeX=0; eqShakeY=0; eqTimer=0;
        meteorTrails=[]; shootingStars=[]; fireworksBursts=[]; fwLaunchers=[];
        nebulaT=0; bloodMoonT=0;
        var count=(type==='storm')      ?POOL:
                  (type==='blizzard')   ?POOL*0.9:
                  (type==='rain')       ?POOL*0.7:
                  (type==='hail')       ?POOL*0.5:
                  (type==='tornado')    ?60:
                  (type==='wind')       ?80:
                  (type==='snow')       ?POOL*0.55:
                  (type==='earthquake') ?30:
                  (type==='meteor')     ?0:0;
        for(var i=0;i<count;i++) particles.push(makeParticle(type));
        if(type==='meteor') {
            for(var m=0;m<12;m++) meteorTrails.push(makeMeteor());
        }
        if(type==='starry'||type==='bloodmoon'||type==='nebula') {
            if(starField.length===0) buildStarField();
            if(type==='starry') { for(var ss=0;ss<4;ss++) shootingStars.push(makeShootingStar()); }
        }
        if(type==='shooting') {
            if(starField.length===0) buildStarField();
            for(var ss2=0;ss2<10;ss2++) shootingStars.push(makeShootingStar());
        }
        if(type==='fireworks') {
            if(starField.length===0) buildStarField();
            for(var fl=0;fl<6;fl++) fwLaunchers.push({timer:rng(0,3000), interval:rng(800,2200), x:rng(W*0.1,W*0.9)});
        }
        /* initialise any custom-render event (no-op for the legacy ones) */
        initCustomEvent(type);
    }

    function makeMeteor() {
        return { x:rng(0,W), y:rng(-H*0.6,-20),
                 vx:rng(3,7), vy:rng(8,16),
                 len:rng(40,100), r:rng(1,3),
                 col:rngI(0,3) /* 0=white,1=orange,2=cyan */ };
    }

    function makeParticle(type) {
        var p={type:type,x:rng(0,W),y:rng(-H,0)};
        if(type==='rain'||type==='storm'){p.vy=rng(10,18);p.vx=rng(-2.0,-0.6);p.len=rng(18,32);}
        else if(type==='snow'||type==='blizzard'){p.vy=rng(0.4,1.8);p.vx=rng(-0.4,0.4);p.r=rng(1.5,3.5);p.sw=rng(0,Math.PI*2);p.swS=rng(0.001,0.003);}
        else if(type==='hail'){p.vy=rng(10,16);p.r=rng(2,5);p.vx=rng(-1,1);}
        else if(type==='wind'){p.y=rng(0,GROUND);p.vy=rng(-0.6,0.6);p.vx=rng(6,14);p.len=rng(30,80);}
        else if(type==='tornado'){p.angle=rng(0,Math.PI*2);p.radius=rng(20,130);p.vy=rng(-3,-7);p.y=GROUND+rng(-60,10);}
        else if(type==='earthquake'){p.x=rng(0,W);p.y=GROUND+rng(0,(H-GROUND)*0.8);p.vx=rng(-4,4);p.vy=rng(-3,-1);p.life=rng(20,60);p.r=rng(3,10);}
        return p;
    }

    function updateParticles(dt) {
        var k=dt/16;
        var type=effType(EVENTS[eventIndex]);
        var i,p;

        if(type==='flood'&&floodRising&&floodY>GROUND-H*0.26) floodY-=0.065*k;
        if(type==='tornado'){tSwayT+=0.0010*dt;tX=W*0.5+Math.sin(tSwayT)*W*0.20;}
        if(type==='earthquake'){eqTimer+=dt; eqShakeX=Math.sin(eqTimer*0.18)*3*(1-Math.min(1,eqTimer/8000)); eqShakeY=Math.cos(eqTimer*0.24)*2*(1-Math.min(1,eqTimer/8000));}
        if(type==='aurora') auroraT+=0.0004*dt;
        if(type==='nebula') nebulaT+=0.0003*dt;
        if(type==='bloodmoon') bloodMoonT+=0.0006*dt;

        /* shooting stars update */
        if(type==='starry'||type==='shooting') {
            for(i=shootingStars.length-1;i>=0;i--) {
                var ss3=shootingStars[i];
                ss3.x+=ss3.vx*k; ss3.y+=ss3.vy*k; ss3.life+=dt;
                if(ss3.life>ss3.maxLife||ss3.x>W+ss3.len||ss3.y>GROUND) {
                    shootingStars[i]=makeShootingStar();
                    shootingStars[i].life=0;
                }
            }
            var target=(type==='shooting')?10:4;
            while(shootingStars.length<target) shootingStars.push(makeShootingStar());
        }

        /* fireworks update */
        if(type==='fireworks') {
            for(var fi=0;fi<fwLaunchers.length;fi++) {
                fwLaunchers[fi].timer-=dt;
                if(fwLaunchers[fi].timer<=0) {
                    fwLaunchers[fi].timer=fwLaunchers[fi].interval;
                    fwLaunchers[fi].x=rng(W*0.08,W*0.92);
                    var burstY=rng(GROUND*0.08, GROUND*0.45);
                    var newBurst=makeFireworkBurst(fwLaunchers[fi].x, burstY);
                    fireworksBursts=fireworksBursts.concat(newBurst);
                }
            }
            for(i=fireworksBursts.length-1;i>=0;i--) {
                var fp=fireworksBursts[i];
                fp.life+=dt; fp.x+=fp.vx*k; fp.y+=fp.vy*k; fp.vy+=fp.gravity*k;
                fp.vx*=Math.pow(0.985,k); fp.vy*=Math.pow(0.985,k);
                if(fp.life>fp.maxLife) fireworksBursts.splice(i,1);
            }
            if(fireworksBursts.length>800) fireworksBursts.splice(0,fireworksBursts.length-800);
        }

        if(type==='meteor'){
            for(i=0;i<meteorTrails.length;i++){
                var m=meteorTrails[i];
                m.x+=m.vx*k; m.y+=m.vy*k;
                if(m.y>H+30){
                    meteorTrails[i]=makeMeteor();
                    splashes.push({x:m.x,r:0,maxR:rng(12,28),life:0,maxLife:rng(400,800),op:0.60});
                }
            }
        }

        for(i=0;i<particles.length;i++){
            p=particles[i];
            if(p.type==='rain'||p.type==='storm'){
                p.x+=p.vx*k; p.y+=p.vy*k;
                if(p.y>=GROUND&&p.y<GROUND+p.vy*k+2&&splashes.length<120){
                    splashes.push({x:p.x,r:0,maxR:rng(2,6),life:0,maxLife:rng(120,220),op:rng(0.25,0.55)});
                }
                if(p.y>H+12){p.y=rng(-80,-10);p.x=rng(0,W);}
                if(p.x<-12) p.x=W+12;
            } else if(p.type==='snow'||p.type==='blizzard'){
                p.sw+=p.swS*dt; p.x+=Math.sin(p.sw)*0.35+p.vx; p.y+=p.vy*k;
                if(p.y>GROUND){p.y=rng(-50,-10);p.x=rng(0,W);}
            } else if(p.type==='hail'){
                p.x+=p.vx*k; p.y+=p.vy*k;
                if(p.y>GROUND){
                    splashes.push({x:p.x,r:0,maxR:rng(3,8),life:0,maxLife:rng(80,160),op:0.55});
                    p.y=rng(-60,-10);p.x=rng(0,W);
                }
            } else if(p.type==='wind'){
                p.x+=p.vx*k; p.y+=p.vy*k;
                if(p.x>W+80){p.x=rng(-80,-10);p.y=rng(0,GROUND);}
            } else if(p.type==='tornado'){
                p.angle+=0.065*k; p.radius=Math.max(0,p.radius-0.04*k); p.y+=p.vy*k;
                if(p.radius<5||p.y<0){p.angle=rng(0,Math.PI*2);p.radius=rng(20,130);p.y=GROUND+rng(-60,10);p.vy=rng(-3,-7);}
            } else if(p.type==='earthquake'){
                p.x+=p.vx*k; p.y+=p.vy*k; p.vy+=0.5*k; p.life-=dt;
                if(p.life<=0||p.y>GROUND+50){
                    p.x=rng(0,W); p.y=GROUND+rng(0,(H-GROUND)*0.8);
                    p.vx=rng(-4,4); p.vy=rng(-3,-1); p.life=rng(20,60); p.r=rng(3,10);
                }
            }
        }

        for(i=splashes.length-1;i>=0;i--){
            var sp=splashes[i]; sp.life+=dt; sp.r=sp.maxR*(sp.life/sp.maxLife);
            if(sp.life>=sp.maxLife) splashes.splice(i,1);
        }

        /* advance per-event state for the invented catastrophes */
        updateCustomEvent(dt);

        if(type==='storm'||type==='meteor'){
            ltTimer+=dt;
            if(ltActive){ltFlash=Math.max(0,ltFlash-dt*0.10);if(ltFlash<=0)ltActive=false;}
            else if(ltTimer>rng(type==='meteor'?800:2200, type==='meteor'?2000:5000)){
                ltTimer=0;ltActive=true;ltFlash=90;
                var lx=rng(W*0.05,W*0.95); ltPts=[{x:lx,y:0}];
                var cy=0;
                while(cy<GROUND){cy+=rng(18,55);ltPts.push({x:ltPts[ltPts.length-1].x+rng(-40,40),y:cy});}
            }
        }
    }

    /* ══════════════════════════════════════════════
       VEHICLE WEATHER-IMPACT OVERLAY
    ══════════════════════════════════════════════ */

    function _carScale(v) {
        var rdH=H-GROUND;
        return Math.max(5, rdH*0.12);
    }
    function _carBodyBottom(v) {
        var rdH=H-GROUND;
        var laneOff = (v.dir===1) ? rdH*0.06 : -rdH*0.06;
        return GROUND + rdH*0.10 + laneOff;
    }
    /* dark/night-like events where headlights are visible */
    function _headlightsOn(type) {
        return type==='storm'||type==='tornado'||type==='earthquake'||type==='meteor'||
               type==='blizzard'||type==='bloodmoon'||type==='starry'||type==='shooting'||
               type==='nebula'||type==='flood'||type==='rain';
    }
    /* Draw the forward beam BEFORE the car so cars in front occlude beams behind them */
    function drawCarBeam(c, v, type) {
        if(!_headlightsOn(type)) return;
        var s = _carScale(v);
        var by = _carBodyBottom(v) + (v.yOff||0);
        /* anchor on the front bumper, at hood-front level (not wheel level) */
        var s0 = (v.type==='bus') ? s*2.05 : (v.type==='truck') ? s*1.25 : s*0.96;
        var bumperX = v.x + v.dir*s0 + (v.xShake||0);
        var headHt = (v.type==='bus') ? by - s*1.10 : (v.type==='truck') ? by - s*0.95 : by - s*0.30;
        var beamLen = 80 + (type==='storm'||type==='blizzard'?28:0);
        var bg = c.createLinearGradient(bumperX, headHt, bumperX + v.dir*beamLen, headHt);
        bg.addColorStop(0,   'rgba(255,250,220,0.70)');
        bg.addColorStop(0.5, 'rgba(255,240,180,0.22)');
        bg.addColorStop(1,   'rgba(255,220,140,0)');
        c.fillStyle = bg;
        c.beginPath();
        c.moveTo(bumperX, headHt-3);
        c.lineTo(bumperX + v.dir*beamLen, headHt-16);
        c.lineTo(bumperX + v.dir*beamLen, headHt+16);
        c.lineTo(bumperX, headHt+3);
        c.closePath();
        c.fill();
        /* hot bulb glow at the bumper, also drawn before the car so it sits "in" the headlight */
        radialGlow(c, bumperX, headHt, 7, 255, 245, 210, 0.55);
    }
    /* Wipers, spray, hazards, accumulation — drawn AFTER the car so they sit on it */
    function drawCarExtras(c, v, type) {
        var s = _carScale(v);
        var by = _carBodyBottom(v) + (v.yOff||0);
        var rainy = (type==='rain'||type==='storm'||type==='flood');
        var hazardy = (type==='tornado'||type==='earthquake'||type==='meteor'||type==='blizzard'||type==='flood');
        var s0 = (v.type==='bus') ? s*2.05 : (v.type==='truck') ? s*1.25 : s*0.96;
        /* hazard tail-light blink at rear bumper, hood-line height */
        if(hazardy) {
            var on = Math.sin(v.hazT*4) > 0;
            if(on) {
                var rearX = v.x - v.dir*s0 + (v.xShake||0);
                var tailY = (v.type==='bus') ? by - s*1.10 : (v.type==='truck') ? by - s*0.95 : by - s*0.30;
                radialGlow(c, rearX, tailY, 7, 255, 140, 20, 0.78);
            }
        }
        if(rainy) {
            /* wiper sweeping windshield in rain */
            var wx = v.x + v.dir*s*0.18 + (v.xShake||0);
            var wy = by - s*0.62;
            var ang = Math.sin(v.wiperT*3)*0.5;
            c.strokeStyle='rgba(30,30,30,0.7)'; c.lineWidth=1.2;
            c.beginPath();
            c.moveTo(wx, wy);
            c.lineTo(wx + Math.cos(ang)*s*0.30, wy - Math.sin(ang)*s*0.18);
            c.stroke();
            /* spray from wheels */
            c.fillStyle='rgba(200,220,240,0.35)';
            for(var sp=0;sp<3;sp++) {
                var sx = v.x - v.dir*s*0.45 + rng(-2,2) + (v.xShake||0);
                var sy = by + s*0.55 + rng(-1,1);
                c.beginPath(); c.arc(sx, sy, rng(0.8,2.2), 0, Math.PI*2); c.fill();
            }
        }
        if(type==='snow'||type==='blizzard'||type==='meteor') {
            c.fillStyle = (type==='meteor') ? 'rgba(50,40,30,0.85)' : 'rgba(245,250,255,0.95)';
            c.fillRect(v.x - s*0.45 + (v.xShake||0), by - s*0.62, s*0.9, 1.6);
        }
    }

    /* ══════════════════════════════════════════════
       DYNAMIC LAYER
    ══════════════════════════════════════════════ */

    function drawDynamic() {
        dynC.clearRect(0,0,W,H);
        var type=effType(EVENTS[eventIndex]);
        var i,p;

        /* ── DESTROYED-BUILDING / WRECKAGE LAYER ──────────────────────────
           Drawn FIRST in dynC so weather (rain, snow, lightning, fog…) and
           the rest of the scene layer above it. This keeps destroyed buildings
           at the same logical z as the live city silhouette. */
        if(typeof drawWreckageLayer==='function') drawWreckageLayer(dynC);
        /* ── AIR-DEFENCE BATTERIES on the ground (low z, cars pass over) ── */
        if(typeof drawAirDefence==='function') drawAirDefence(dynC);

        /* wet pavement reflections */
        if(type==='rain'||type==='storm'||type==='flood'){
            var refA=dynC.createLinearGradient(0,GROUND-3,0,GROUND+50);
            refA.addColorStop(0,'rgba(255,210,70,0.18)');
            refA.addColorStop(0.5,'rgba(255,210,70,0.07)');
            refA.addColorStop(1,'rgba(0,0,0,0)');
            dynC.fillStyle=refA; dynC.fillRect(0,GROUND-3,W,53);
            var refB=dynC.createLinearGradient(0,GROUND-3,0,GROUND+50);
            refB.addColorStop(0,'rgba(60,130,220,0.12)');
            refB.addColorStop(0.6,'rgba(60,130,220,0.04)');
            refB.addColorStop(1,'rgba(0,0,0,0)');
            dynC.fillStyle=refB; dynC.fillRect(0,GROUND-3,W,53);
        }

        if(type==='heat'){
            dynC.fillStyle='rgba(180,60,0,0.08)';
            dynC.fillRect(0,GROUND-H*0.14,W,H*0.14);
        }

        /* particles */
        for(i=0;i<particles.length;i++){
            p=particles[i];
            if(p.type==='rain'||p.type==='storm'){
                dynC.strokeStyle=p.type==='storm'?'rgba(180,210,255,0.72)':'rgba(160,200,240,0.55)';
                dynC.lineWidth=p.type==='storm'?1.5:1;
                dynC.beginPath(); dynC.moveTo(p.x,p.y); dynC.lineTo(p.x+p.vx*0.5,p.y+p.len); dynC.stroke();
            } else if(p.type==='snow'||p.type==='blizzard'){
                dynC.fillStyle='#ffffff';
                dynC.beginPath(); dynC.arc(p.x,p.y,p.r,0,Math.PI*2); dynC.fill();
            } else if(p.type==='hail'){
                dynC.fillStyle='#d0eeff';
                dynC.beginPath(); dynC.arc(p.x,p.y,p.r,0,Math.PI*2); dynC.fill();
                dynC.strokeStyle='#90c8e8'; dynC.lineWidth=0.6; dynC.stroke();
            } else if(p.type==='wind'){
                dynC.strokeStyle='rgba(200,220,255,0.38)'; dynC.lineWidth=1;
                dynC.beginPath(); dynC.moveTo(p.x,p.y); dynC.lineTo(p.x+p.len,p.y); dynC.stroke();
            } else if(p.type==='tornado'){
                var tx2=tX+Math.cos(p.angle)*p.radius;
                dynC.fillStyle='#3a3028';
                dynC.beginPath(); dynC.arc(tx2,p.y,2.5,0,Math.PI*2); dynC.fill();
            } else if(p.type==='earthquake'){
                dynC.fillStyle='rgba(160,120,60,'+(p.life/60)*0.70+')';
                dynC.beginPath(); dynC.arc(p.x,p.y,p.r,0,Math.PI*2); dynC.fill();
            }
        }

        /* aurora borealis */
        if(type==='aurora'){
            for(var ab=0;ab<5;ab++){
                var aFrac=ab/5;
                var aY=GROUND*(0.15+aFrac*0.35);
                var aG=dynC.createLinearGradient(0,aY-80,0,aY+40);
                var cols3=['rgba(0,255,120,','rgba(0,200,255,','rgba(120,80,255,','rgba(255,80,200,','rgba(0,255,180,'];
                aG.addColorStop(0,cols3[ab]+'0)');
                aG.addColorStop(0.4,cols3[ab]+'0.22)');
                aG.addColorStop(1,cols3[ab]+'0)');
                dynC.fillStyle=aG;
                dynC.beginPath();
                for(var aw=0;aw<=W;aw+=8){
                    var ay2=aY+Math.sin(aw*0.012+auroraT+ab*1.3)*28+Math.sin(aw*0.006+auroraT*0.7)*18;
                    aw===0?dynC.moveTo(aw,ay2):dynC.lineTo(aw,ay2);
                }
                dynC.lineTo(W,aY+80); dynC.lineTo(0,aY+80); dynC.closePath(); dynC.fill();
            }
        }

        /* ── starfield ── shown for starry / shooting / fireworks / bloodmoon / nebula */
        if(type==='starry'||type==='shooting'||type==='fireworks'||type==='bloodmoon'||type==='nebula') {
            for(var sfi=0;sfi<starField.length;sfi++) {
                var sf=starField[sfi];
                var tw=0.5+0.5*Math.sin(Date.now()*sf.twinkleSpeed+sf.twinkleOffset);
                var alpha=sf.bright*(0.55+0.45*tw);
                var starR=sf.r*(type==='starry'?1.4:type==='nebula'?1.2:1.0);
                dynC.fillStyle='rgba(255,255,255,'+alpha+')';
                dynC.beginPath(); dynC.arc(sf.x,sf.y,starR,0,Math.PI*2); dynC.fill();
                /* twinkle glow on bright stars */
                if(sf.bright>0.75&&tw>0.6) radialGlow(dynC,sf.x,sf.y,starR*4,220,230,255,alpha*0.35);
            }
        }

        /* ── milky way band for starry ── */
        if(type==='starry') {
            var mwG=dynC.createLinearGradient(0,GROUND*0.05,W*0.8,GROUND*0.55);
            mwG.addColorStop(0,'rgba(200,210,255,0)');
            mwG.addColorStop(0.3,'rgba(200,215,255,0.07)');
            mwG.addColorStop(0.5,'rgba(220,225,255,0.11)');
            mwG.addColorStop(0.7,'rgba(200,215,255,0.07)');
            mwG.addColorStop(1,'rgba(200,210,255,0)');
            dynC.fillStyle=mwG; dynC.fillRect(0,0,W,GROUND*0.85);
            /* milky way star clusters */
            for(var mwi=0;mwi<40;mwi++) {
                var mwx=rng(W*0.05,W*0.75), mwy=rng(0,GROUND*0.6);
                dynC.fillStyle='rgba(230,235,255,'+(rng(0.04,0.12))+')';
                dynC.beginPath(); dynC.ellipse(mwx,mwy,rng(4,18),rng(2,8),rng(0,Math.PI),0,Math.PI*2); dynC.fill();
            }
        }

        /* ── nebula clouds ── */
        if(type==='nebula') {
            var nbCols=[
                [80,0,200],[0,80,200],[200,0,120],
                [0,180,160],[120,0,200],[60,0,160]
            ];
            for(var nb=0;nb<8;nb++) {
                var nc3=nbCols[nb%nbCols.length];
                var nbx=W*(0.1+nb*0.11+Math.sin(nebulaT+nb*1.3)*0.06);
                var nby=GROUND*(0.08+Math.sin(nb*0.7+nebulaT*0.8)*0.18);
                var nbr=rng(60,160);
                var nbG=dynC.createRadialGradient(nbx,nby,0,nbx,nby,nbr);
                nbG.addColorStop(0,'rgba('+nc3[0]+','+nc3[1]+','+nc3[2]+',0.22)');
                nbG.addColorStop(0.5,'rgba('+nc3[0]+','+nc3[1]+','+nc3[2]+',0.10)');
                nbG.addColorStop(1,'rgba('+nc3[0]+','+nc3[1]+','+nc3[2]+',0)');
                dynC.fillStyle=nbG; dynC.fillRect(nbx-nbr,nby-nbr,nbr*2,nbr*2);
            }
        }

        /* ── blood moon ── */
        if(type==='bloodmoon') {
            var moonX=W*0.72, moonY=H*0.18;
            var moonR=Math.min(W,H)*0.07;
            radialGlow(dynC,moonX,moonY,moonR*4.5,200,20,0,0.35);
            radialGlow(dynC,moonX,moonY,moonR*2.5,255,60,0,0.50);
            var moonGrd=dynC.createRadialGradient(moonX-moonR*0.3,moonY-moonR*0.3,0,moonX,moonY,moonR);
            moonGrd.addColorStop(0,'rgba(255,90,30,0.98)');
            moonGrd.addColorStop(0.5,'rgba(200,30,10,0.97)');
            moonGrd.addColorStop(1,'rgba(120,10,5,0.96)');
            dynC.fillStyle=moonGrd; dynC.beginPath(); dynC.arc(moonX,moonY,moonR,0,Math.PI*2); dynC.fill();
            /* crater texture */
            dynC.strokeStyle='rgba(80,10,0,0.35)'; dynC.lineWidth=1;
            for(var cr=0;cr<6;cr++) {
                var crx=moonX+rng(-moonR*0.6,moonR*0.6), cry=moonY+rng(-moonR*0.6,moonR*0.6);
                dynC.beginPath(); dynC.arc(crx,cry,rng(moonR*0.06,moonR*0.18),0,Math.PI*2); dynC.stroke();
            }
            /* eerie red cloud wisps */
            for(var rw=0;rw<5;rw++) {
                var rwx=(rw*W*0.22+Date.now()*0.006)%W, rwy=GROUND*(0.04+rw*0.08);
                dynC.fillStyle='rgba(180,10,0,0.06)';
                dynC.beginPath(); dynC.ellipse(rwx,rwy,120+rw*30,20+rw*5,0,0,Math.PI*2); dynC.fill();
            }
        }

        /* ── shooting stars ── */
        if(type==='starry'||type==='shooting') {
            for(var ssi=0;ssi<shootingStars.length;ssi++) {
                var sst=shootingStars[ssi];
                if(sst.life<100) continue;
                var ssCols=['rgba(255,255,255,','rgba(80,240,255,','rgba(255,220,80,'];
                var sstG=dynC.createLinearGradient(sst.x,sst.y, sst.x-sst.vx*sst.len/sst.vy, sst.y-sst.len);
                sstG.addColorStop(0,ssCols[sst.col]+'0.95)');
                sstG.addColorStop(1,ssCols[sst.col]+'0)');
                dynC.strokeStyle=sstG; dynC.lineWidth=sst.r;
                dynC.beginPath(); dynC.moveTo(sst.x,sst.y);
                dynC.lineTo(sst.x-sst.vx*sst.len/sst.vy, sst.y-sst.len); dynC.stroke();
                radialGlow(dynC,sst.x,sst.y,sst.r*6,255,240,200,0.60);
                dynC.fillStyle=ssCols[sst.col]+'1)';
                dynC.beginPath(); dynC.arc(sst.x,sst.y,sst.r,0,Math.PI*2); dynC.fill();
            }
        }

        /* ── fireworks ── */
        if(type==='fireworks') {
            for(var fbi=0;fbi<fireworksBursts.length;fbi++) {
                var fb=fireworksBursts[fbi];
                var fpAlpha=1-fb.life/fb.maxLife;
                var fpR=fb.r*(1-fb.life/fb.maxLife*0.5);
                if(fpAlpha<0.05) continue;
                dynC.fillStyle='rgba('+fb.rr+','+fb.gg+','+fb.bb+','+fpAlpha+')';
                dynC.beginPath(); dynC.arc(fb.x,fb.y,fpR,0,Math.PI*2); dynC.fill();
                if(fpAlpha>0.35) radialGlow(dynC,fb.x,fb.y,fpR*3.5,fb.rr,fb.gg,fb.bb,fpAlpha*0.30);
            }
        }

        /* falling meteors */
        if(type==='meteor'){
            for(var mi=0;mi<meteorTrails.length;mi++){
                var mt=meteorTrails[mi];
                var mCols=['rgba(255,255,240,','rgba(255,160,60,','rgba(80,220,255,'];
                var mG=dynC.createLinearGradient(mt.x,mt.y, mt.x-mt.vx*mt.len/mt.vy,mt.y-mt.len);
                mG.addColorStop(0,mCols[mt.col]+'0.95)');
                mG.addColorStop(1,mCols[mt.col]+'0)');
                dynC.strokeStyle=mG; dynC.lineWidth=mt.r;
                dynC.beginPath(); dynC.moveTo(mt.x,mt.y);
                dynC.lineTo(mt.x-mt.vx*mt.len/mt.vy, mt.y-mt.len); dynC.stroke();
                /* bright head */
                radialGlow(dynC,mt.x,mt.y,mt.r*5,255,220,160,0.55);
                dynC.fillStyle=mCols[mt.col]+'1)';
                dynC.beginPath(); dynC.arc(mt.x,mt.y,mt.r,0,Math.PI*2); dynC.fill();
            }
        }

        /* earthquake: screen shake applied via ctx offset in tick(), crack lines here */
        if(type==='earthquake'){
            dynC.strokeStyle='rgba(100,60,20,0.55)'; dynC.lineWidth=1.5;
            for(var qi=0;qi<4;qi++){
                var qx=(qi*W*0.28+eqTimer*0.3)%W;
                dynC.beginPath(); dynC.moveTo(qx,GROUND);
                dynC.lineTo(qx+rng(-20,20),GROUND+(H-GROUND)*0.4);
                dynC.stroke();
            }
            /* ground dust clouds */
            for(var qd=0;qd<6;qd++){
                var qdx=(qd*W/5+eqTimer*0.5)%W;
                radialGlow(dynC, qdx,GROUND, 30+Math.sin(eqTimer*0.05+qd)*10, 180,140,80, 0.20);
            }
        }

        if(type==='tornado'){
            for(var seg=0;seg<22;seg++){
                var frac=seg/22;
                var fw=6+frac*88;
                var fy2=frac*GROUND;
                dynC.fillStyle='rgba(40,35,15,'+(0.07+frac*0.26)+')';
                dynC.beginPath(); dynC.ellipse(tX,fy2,fw,fw*0.28,0,0,Math.PI*2); dynC.fill();
            }
        }

        if(type==='flood'&&floodY<GROUND){
            dynC.fillStyle='rgba(10,40,100,0.50)';
            dynC.fillRect(0,floodY,W,GROUND-floodY);
            dynC.strokeStyle='rgba(80,160,255,0.45)'; dynC.lineWidth=2;
            dynC.beginPath();
            for(var wx=0;wx<=W;wx+=28){
                var wy2=floodY+Math.sin(wx*0.04+tSwayT*0.01)*3;
                wx===0?dynC.moveTo(wx,wy2):dynC.lineTo(wx,wy2);
            }
            dynC.stroke();
        }

        if(ltActive&&ltFlash>0&&ltPts.length>1){
            dynC.fillStyle='rgba(200,220,255,'+(Math.min(0.22,ltFlash/90*0.22))+')';
            dynC.fillRect(0,0,W,H);
            dynC.strokeStyle='rgba(140,180,255,0.55)'; dynC.lineWidth=5;
            dynC.beginPath(); dynC.moveTo(ltPts[0].x,ltPts[0].y);
            for(var lp=1;lp<ltPts.length;lp++) dynC.lineTo(ltPts[lp].x,ltPts[lp].y);
            dynC.stroke();
            dynC.strokeStyle='#ffffff'; dynC.lineWidth=1.5;
            dynC.beginPath(); dynC.moveTo(ltPts[0].x,ltPts[0].y);
            for(var lp2=1;lp2<ltPts.length;lp2++) dynC.lineTo(ltPts[lp2].x,ltPts[lp2].y);
            dynC.stroke();
        }

        if(splashes.length>0){
            dynC.strokeStyle='rgba(180,210,240,0.60)'; dynC.lineWidth=0.8;
            for(var si=0;si<splashes.length;si++){
                var sp=splashes[si];
                dynC.globalAlpha=sp.op*(1-sp.life/sp.maxLife);
                dynC.beginPath(); dynC.ellipse(sp.x,GROUND-1,sp.r,sp.r*0.4,0,0,Math.PI*2); dynC.stroke();
            }
            dynC.globalAlpha=1;
        }

        /* ESB rotating colored beacon — NYC only */
        esbAngle+=0.008;
        if(currentCityIndex===0) {
            var esbX=W*0.63;
            var esbY=GROUND-H*0.55*0.88;
            var beaconColors=[[255,80,0],[255,180,0],[0,180,255],[255,60,180]];
            var bc2=beaconColors[Math.floor(esbAngle/0.5)%beaconColors.length];
            var beamLen=W*0.22;
            var bx1=esbX+Math.cos(esbAngle)*beamLen;
            var by1=esbY+Math.sin(esbAngle)*beamLen*0.3;
            var bg2=dynC.createLinearGradient(esbX,esbY,bx1,by1);
            bg2.addColorStop(0,'rgba('+bc2[0]+','+bc2[1]+','+bc2[2]+',0.55)');
            bg2.addColorStop(1,'rgba('+bc2[0]+','+bc2[1]+','+bc2[2]+',0)');
            dynC.strokeStyle=bg2; dynC.lineWidth=3;
            dynC.beginPath(); dynC.moveTo(esbX,esbY); dynC.lineTo(bx1,by1); dynC.stroke();
            var bx2=esbX+Math.cos(esbAngle+Math.PI)*beamLen;
            var by2=esbY+Math.sin(esbAngle+Math.PI)*beamLen*0.3;
            var bg3=dynC.createLinearGradient(esbX,esbY,bx2,by2);
            bg3.addColorStop(0,'rgba('+bc2[0]+','+bc2[1]+','+bc2[2]+',0.55)');
            bg3.addColorStop(1,'rgba('+bc2[0]+','+bc2[1]+','+bc2[2]+',0)');
            dynC.strokeStyle=bg3; dynC.lineWidth=3;
            dynC.beginPath(); dynC.moveTo(esbX,esbY); dynC.lineTo(bx2,by2); dynC.stroke();
            radialGlow(dynC, esbX,esbY, 22, bc2[0],bc2[1],bc2[2], 0.50);
        }

        /* Ground-level custom-event effects (acid puddles, lava
           craters, plasma scorch points on the road) must render
           BEFORE vehicles so the cars sit on top of them — drive
           through the puddle, not on top of it visually. */
        drawCustomEventGround(dynC);

        /* sort vehicles back-to-front so closer cars occlude farther ones:
           upper lane (dir=-1) drawn first; within a lane, the "back" of the lane drawn first */
        var sortedV = vehicles.slice().sort(function(a,b){
            if(a.dir!==b.dir) return (a.dir===1?1:-1) - (b.dir===1?1:-1);
            return a.dir===1 ? a.x-b.x : b.x-a.x;
        });
        /* Suppress ordinary civilian traffic during a military parade —
           the street is taken over by the parade vehicles. The reverse
           toggles back when the parade ends. */
        if (!paradeOn) {
            for(var vi=0;vi<sortedV.length;vi++) {
                var V=sortedV[vi];
                /* skip cars that are hidden inside an alien saucer */
                if (V._absHidden && !V._absLifting) continue;
                var off = (V.xShake||0)||(V.yOff||0);
                if(off || V._absLifting){
                    dynC.save();
                    if (V._absLifting && V._absY !== undefined){
                        /* during lift, override draw y by translating
                           so the existing drawVehicle code stays
                           untouched */
                        var rdHV = H - GROUND;
                        var laneOffV = (V.dir===1) ? rdHV*0.06 : -rdHV*0.06;
                        var baseY = GROUND + rdHV*0.10 + laneOffV;
                        dynC.translate(0, V._absY - baseY);
                    } else if (off) {
                        dynC.translate(V.xShake||0, V.yOff||0);
                    }
                }
                drawVehicle(dynC,V);
                drawCarExtras(dynC, V, type);
                /* ALIEN-CAR GLOW — green hover-halo + electric arcs
                   while the car is "alienized". During morph phase the
                   glow pulses fast and fades out. */
                if (V._alienized){
                    var rdHV2 = H - GROUND;
                    var laneOffV2 = (V.dir===1) ? rdHV2*0.06 : -rdHV2*0.06;
                    var byV2 = GROUND + rdHV2*0.10 + laneOffV2;
                    var carScale = Math.max(5, rdHV2*0.12);
                    var morphProg = V._morphing ? (V._morphT / V._morphDur) : 0;
                    var glowA = (1 - morphProg) * (0.55 + Math.sin(performance.now()*0.012 + V.x*0.05)*0.25);
                    var pulseFast = V._morphing ? Math.sin(V._morphT*0.05) * 0.5 + 0.5 : 0;
                    /* underbelly green hover glow */
                    var gh = dynC.createRadialGradient(V.x, byV2+2, 1, V.x, byV2+2, carScale*1.4);
                    gh.addColorStop(0, 'rgba(100,255,140,' + glowA + ')');
                    gh.addColorStop(0.5, 'rgba(60,200,100,' + (glowA*0.55) + ')');
                    gh.addColorStop(1, 'rgba(60,200,100,0)');
                    dynC.fillStyle = gh;
                    dynC.beginPath();
                    dynC.ellipse(V.x, byV2+2, carScale*1.4, carScale*0.55, 0, 0, Math.PI*2);
                    dynC.fill();
                    /* electric arcs over body — 3 short jagged bolts */
                    for (var ea=0; ea<3; ea++){
                        var eaOff = (ea-1) * carScale*0.35;
                        var ax0 = V.x + eaOff, ay0 = byV2 - carScale*0.55;
                        var jitter1 = rng(-3, 3), jitter2 = rng(-3, 3);
                        dynC.strokeStyle = 'rgba(180,255,220,' + (glowA*0.85) + ')';
                        dynC.lineWidth = 1.2;
                        dynC.beginPath();
                        dynC.moveTo(ax0 - 4, ay0 - 2);
                        dynC.lineTo(ax0 + jitter1, ay0 - 6);
                        dynC.lineTo(ax0 + 4, ay0 - 4);
                        dynC.stroke();
                    }
                    /* alien chassis tint — green wash on body */
                    dynC.fillStyle = 'rgba(120,255,150,' + (glowA*0.35) + ')';
                    dynC.fillRect(V.x - carScale*0.55, byV2 - carScale*0.5, carScale*1.1, carScale*0.5);
                    /* eyes-as-headlights — bright green dots */
                    var ed = V.dir;
                    dynC.fillStyle = 'rgba(180,255,160,' + glowA + ')';
                    dynC.beginPath(); dynC.arc(V.x + ed*carScale*0.50, byV2 - carScale*0.22, 1.6, 0, Math.PI*2); dynC.fill();
                    dynC.beginPath(); dynC.arc(V.x + ed*carScale*0.50, byV2 - carScale*0.10, 1.6, 0, Math.PI*2); dynC.fill();
                    /* morph ripple ring */
                    if (V._morphing){
                        dynC.strokeStyle = 'rgba(160,255,200,' + (1 - morphProg) + ')';
                        dynC.lineWidth = 1.4;
                        dynC.beginPath();
                        dynC.ellipse(V.x, byV2 - carScale*0.20,
                                     carScale*0.6 + morphProg*carScale*0.8,
                                     carScale*0.2 + morphProg*carScale*0.3,
                                     0, 0, Math.PI*2);
                        dynC.stroke();
                    }
                }
                if(off || V._absLifting) dynC.restore();
            }
        }
        drawPeds(dynC);

        /* airplane transition */
        if(airplane) drawAirplane(dynC);

        /* city label */
        if(cityLabelTimer>0) {
            var alpha=Math.min(1,cityLabelTimer/400)*Math.min(1,(cityLabelTimer)/1)*1;
            alpha=cityLabelTimer>2500?(3000-cityLabelTimer)/500:Math.min(1,cityLabelTimer/400);
            alpha=Math.max(0,alpha);
            var fs=Math.round(H*0.048);
            dynC.font='bold '+fs+'px "Arial Black",Arial,sans-serif';
            dynC.textAlign='center';
            dynC.textBaseline='middle';
            dynC.fillStyle='rgba(255,255,255,'+alpha*0.22+')';
            dynC.fillText(CITIES[currentCityIndex].name,W/2+2,H*0.16+2);
            dynC.fillStyle='rgba(255,255,255,'+alpha+')';
            dynC.fillText(CITIES[currentCityIndex].name,W/2,H*0.16);
            dynC.textBaseline='alphabetic';
        }

        /* invented catastrophes — paint LAST on the dynamic canvas
           so their effects sit above traffic, peds, and standard
           weather particles. */
        drawCustomEvent(dynC);
    }

    function drawAirplane(c) {
        var pl=airplane, x=pl.x, y=pl.y, d=pl.dir;
        var t=pl.t||0;

        /* ── contrail — world space, rendered before the plane ── */
        if(pl.trail&&pl.trail.length>1) {
            for(var tri=0;tri<pl.trail.length-1;tri++) {
                var tp=pl.trail[tri];
                var ageFrac=tp.age/5000;
                var trAlpha=(1-ageFrac)*(1-ageFrac)*0.50;
                if(trAlpha<0.008) continue;
                var trW=1.0+ageFrac*13;
                /* two engine lanes, separated vertically */
                for(var trLane=-1;trLane<=1;trLane+=2) {
                    c.fillStyle='rgba(238,244,255,'+trAlpha+')';
                    c.beginPath();
                    c.ellipse(tp.x, tp.y+trLane*(2+ageFrac*3.5),
                              trW, trW*0.28, 0, 0, Math.PI*2);
                    c.fill();
                }
            }
        }

        /* ── all plane art in local space (nose = +x) ── */
        c.save();
        c.translate(x,y);
        if(d<0) c.scale(-1,1);

        /* scale: small & crisp — ~55-60px on a 1080p screen */
        var sc=Math.max(0.42, Math.min(0.54, Math.min(W,H)/1900));
        c.scale(sc,sc);

        /* very subtle bank that follows the altitude sine wave */
        var bankAngle=Math.sin(t*0.00042)*0.020;
        c.rotate(bankAngle);

        /* ── exhaust heat bloom (behind everything) ── */
        for(var el=0;el<3;el++) {
            var eR=7+el*7, eA=0.15-el*0.04;
            var exG=c.createRadialGradient(-53+el*4,21,0,-53+el*4,21,eR);
            exG.addColorStop(0,'rgba(215,195,140,'+eA+')');
            exG.addColorStop(1,'rgba(195,160,90,0)');
            c.fillStyle=exG; c.fillRect(-53+el*4-eR,21-eR,eR*2,eR*2);
        }

        /* ── horizontal stabilizer (draw first — tail covers base) ── */
        c.fillStyle='#788898'; c.strokeStyle='#50606e'; c.lineWidth=0.70;
        c.beginPath();
        c.moveTo(-44,2); c.lineTo(-58,14); c.lineTo(-61,11); c.lineTo(-46,0);
        c.closePath(); c.fill(); c.stroke();

        /* ── vertical tail fin ── */
        c.fillStyle='#1a3570'; c.strokeStyle='#102260'; c.lineWidth=0.80;
        c.beginPath();
        c.moveTo(-43,-2);
        c.bezierCurveTo(-45,-7,-53,-17,-57,-24);  /* swept leading edge */
        c.bezierCurveTo(-55,-24,-53,-21,-51,-17);  /* rounded tip */
        c.bezierCurveTo(-49,-12,-47,-6,-43,-2);    /* trailing edge */
        c.closePath(); c.fill(); c.stroke();
        /* fin highlight — subtle specular */
        c.fillStyle='rgba(65,120,215,0.22)';
        c.beginPath();
        c.moveTo(-43,-2); c.bezierCurveTo(-45,-8,-53,-18,-57,-24);
        c.bezierCurveTo(-56,-23,-54,-19,-52,-15);
        c.bezierCurveTo(-50,-10,-46,-5,-43,-2);
        c.closePath(); c.fill();

        /* ── main wing ── swept 32°, winglet upswept tip ── */
        c.fillStyle='#788898'; c.strokeStyle='#506070'; c.lineWidth=0.80;
        c.beginPath();
        c.moveTo(10, 4);   /* root LE */
        c.lineTo(-33,30);  /* tip LE */
        c.lineTo(-37,21);  /* winglet tip (angled up) */
        c.lineTo(-35,19);  /* winglet inner face */
        c.lineTo(-39,32);  /* tip TE */
        c.lineTo( 1,  8);  /* root TE */
        c.closePath(); c.fill(); c.stroke();
        /* upper wing surface highlight */
        c.fillStyle='rgba(165,195,218,0.20)';
        c.beginPath();
        c.moveTo(8,4); c.lineTo(-31,28); c.lineTo(-33,27); c.lineTo(6,5);
        c.closePath(); c.fill();
        /* flap hinge line */
        c.strokeStyle='rgba(36,50,60,0.34)'; c.lineWidth=0.55;
        c.beginPath(); c.moveTo(-1,8); c.lineTo(-29,31); c.stroke();
        /* aileron panel */
        c.beginPath(); c.moveTo(-26,30); c.lineTo(-37,33); c.stroke();

        /* ── engine pylon ── */
        c.fillStyle='#62748a'; c.strokeStyle='#485868'; c.lineWidth=0.65;
        c.beginPath();
        c.moveTo(-11,13); c.lineTo(-9,21); c.lineTo(-5,21); c.lineTo(-3,14);
        c.closePath(); c.fill(); c.stroke();

        /* ── engine nacelle — CFM LEAP style ── */
        /* main barrel */
        c.fillStyle='#62748a'; c.strokeStyle='#4a5c6a'; c.lineWidth=0.80;
        c.beginPath(); c.ellipse(-15,23,14,4.5,-0.10,0,Math.PI*2); c.fill(); c.stroke();
        /* nacelle top specular */
        c.fillStyle='rgba(150,188,215,0.28)';
        c.beginPath(); c.ellipse(-15,19.5,10,2.0,-0.10,0,Math.PI); c.fill();
        /* inlet cowl — nearly circular bell mouth */
        c.fillStyle='#14202c';
        c.beginPath(); c.ellipse(-27,20,4.4,4.0,-0.10,0,Math.PI*2); c.fill();
        /* fan disc — high-bypass blue-grey */
        c.fillStyle='rgba(58,105,158,0.68)';
        c.beginPath(); c.ellipse(-27,20,3.5,3.2,-0.10,0,Math.PI*2); c.fill();
        /* fan hub highlight */
        c.fillStyle='rgba(130,175,225,0.65)';
        c.beginPath(); c.arc(-27,20,1.1,0,Math.PI*2); c.fill();
        /* inlet lip specular */
        c.strokeStyle='rgba(95,150,210,0.42)'; c.lineWidth=0.5;
        c.beginPath(); c.arc(-27,20,4.2,-1.1,0.35); c.stroke();
        /* exhaust nozzle — hot core */
        c.fillStyle='rgba(200,182,132,0.42)';
        c.beginPath(); c.ellipse(-3,23,3.5,2.8,-0.10,0,Math.PI*2); c.fill();
        /* exhaust shimmer streak */
        c.strokeStyle='rgba(220,195,130,0.28)'; c.lineWidth=0.5;
        c.beginPath(); c.moveTo(-3,21); c.lineTo(6,21); c.stroke();
        c.beginPath(); c.moveTo(-2,23); c.lineTo(8,23); c.stroke();

        /* ── fuselage (drawn over wing root / fin base) ── */
        /* base shape: smooth tube tapering at both ends */
        c.fillStyle='#f2f5ff'; c.strokeStyle='#b6c0d0'; c.lineWidth=0.80;
        c.beginPath();
        c.moveTo(-56,0);                                    /* tail point */
        c.bezierCurveTo(-44,4, -6,6,  36,5);               /* belly sweep */
        c.bezierCurveTo( 50,4, 60,2,  64,0);               /* nose belly */
        c.bezierCurveTo( 60,-2,50,-4, 36,-5);              /* nose top */
        c.bezierCurveTo( -6,-6,-44,-3,-56,0);               /* spine to tail */
        c.closePath(); c.fill(); c.stroke();

        /* cheatline — clip blue upper stripe + gold divider */
        c.save();
        c.beginPath();
        c.moveTo(-56,0);
        c.bezierCurveTo(-44,4, -6,6, 36,5);
        c.bezierCurveTo(50,4, 60,2, 64,0);
        c.bezierCurveTo(60,-2,50,-4,36,-5);
        c.bezierCurveTo(-6,-6,-44,-3,-56,0);
        c.closePath(); c.clip();
        c.fillStyle='#192f6a';                              /* royal blue */
        c.fillRect(-60,-8,132,5.0);                         /* top band: y -8→-3 */
        c.fillStyle='rgba(205,162,30,0.94)';                /* gold stripe */
        c.fillRect(-60,-3.2,132,1.1);
        c.restore();

        /* belly shadow */
        c.fillStyle='rgba(0,0,0,0.07)';
        c.beginPath();
        c.moveTo(-50,2); c.bezierCurveTo(-18,8,18,8,50,4);
        c.bezierCurveTo(18,5,-18,5,-50,2); c.closePath(); c.fill();

        /* top fuselage reflection */
        c.fillStyle='rgba(210,228,255,0.13)';
        c.beginPath();
        c.moveTo(-32,-4.5); c.bezierCurveTo(-8,-5.5,16,-5.5,36,-4.5);
        c.bezierCurveTo(16,-4.5,-8,-4.5,-32,-4.5); c.closePath(); c.fill();

        /* ── nose cone ── */
        c.fillStyle='#cad2e4'; c.strokeStyle='#96a0b4'; c.lineWidth=0.70;
        c.beginPath();
        c.moveTo(63,2.8);
        c.bezierCurveTo(68,1.8, 75,0.8, 80,0);
        c.bezierCurveTo(75,-0.8,68,-1.8,63,-2.5);
        c.closePath(); c.fill(); c.stroke();
        /* weather radar dome — dark composite */
        c.fillStyle='#20283a';
        c.beginPath(); c.arc(80,0,1.8,0,Math.PI*2); c.fill();

        /* ── cockpit windows — slanted band ── */
        c.fillStyle='#111e2c';
        c.beginPath(); c.ellipse(50,-3.5,5.5,2.4,0.12,0,Math.PI*2); c.fill();
        c.strokeStyle='rgba(125,185,232,0.52)'; c.lineWidth=0.40; c.stroke();
        /* cockpit glass reflection */
        c.fillStyle='rgba(65,155,255,0.22)';
        c.beginPath(); c.ellipse(48,-4.5,2.3,1.0,0.12,0,Math.PI*2); c.fill();

        /* ── cabin windows ── 16 uniformly spaced ── */
        c.fillStyle='rgba(125,205,255,0.88)';
        for(var wi=0;wi<18;wi++) {
            var winX=36-wi*5.5; if(winX<-40) break;
            c.fillRect(winX-1.8,-3.0,3.0,2.4);
        }
        /* window glint */
        c.fillStyle='rgba(255,255,255,0.38)';
        for(var wir=0;wir<18;wir++) {
            var winRX=36-wir*5.5; if(winRX<-40) break;
            c.fillRect(winRX-1.8,-3.0,1.3,0.72);
        }

        /* ── gear fairings (retracted) ── */
        c.fillStyle='rgba(38,48,62,0.66)'; c.strokeStyle='rgba(26,34,46,0.42)'; c.lineWidth=0.50;
        c.beginPath(); c.ellipse(2,7,7.5,2.8,0,0,Math.PI*2); c.fill(); c.stroke();
        c.beginPath(); c.ellipse(50,4,4.5,1.8,0,0,Math.PI*2); c.fill(); c.stroke();

        /* ── nose landing light ── */
        radialGlow(c,80,0,12,218,240,255,0.72);
        c.fillStyle='rgba(230,248,255,0.96)';
        c.beginPath(); c.arc(80,0,1.4,0,Math.PI*2); c.fill();

        /* ── anti-collision strobe on fin tip — blinks ── */
        if(Math.floor(t/1100)%2===0) {
            radialGlow(c,-57,-24,9,255,45,45,0.90);
            c.fillStyle='#ff1c1c';
            c.beginPath(); c.arc(-57,-24,2.0,0,Math.PI*2); c.fill();
        }

        /* ── nav lights ── */
        /* port wingtip — red */
        radialGlow(c,-40,27,6,255,20,20,0.82);
        c.fillStyle='#ff0e0e';
        c.beginPath(); c.arc(-40,27,2.0,0,Math.PI*2); c.fill();
        /* tail — white */
        radialGlow(c,-60,0,6,248,255,232,0.68);
        c.fillStyle='#f6fff0';
        c.beginPath(); c.arc(-60,0,1.6,0,Math.PI*2); c.fill();

        c.restore();
    }

    /* ══════════════════════════════════════════════
       WINDOW FLICKER
    ══════════════════════════════════════════════ */

    function flickerWindows() {
        /* landmarks */
        for(var i=0;i<LM.length;i++){
            var lm=LM[i];
            if(!lm.wins) continue;
            var count=rngI(2,6);
            for(var k=0;k<count;k++){
                lm.wins[rngI(0,lm.wins.length)]=WIN_POOL[rngI(0,WIN_POOL.length)];
            }
        }
        /* bg buildings */
        for(var i=0;i<BGBUILDS.length;i++){
            var b=BGBUILDS[i];
            if(!b.wins||b.wins.length===0) continue;
            var count2=rngI(1,4);
            for(var k2=0;k2<count2;k2++){
                b.wins[rngI(0,b.wins.length)]=WIN_POOL[rngI(0,WIN_POOL.length)];
            }
        }
        cityBuilt=false;
    }

    /* ══════════════════════════════════════════════
       MAIN LOOP
    ══════════════════════════════════════════════ */

    /* ── perf / a11y gates: reduced-motion users get a single static frame;
       small viewports throttle to ~30fps to save battery on phones. */
    var _reduceMotionMQ = (typeof window !== 'undefined' && window.matchMedia)
        ? window.matchMedia('(prefers-reduced-motion: reduce)') : null;
    var _reduceMotion = _reduceMotionMQ ? _reduceMotionMQ.matches : false;
    if (_reduceMotionMQ && _reduceMotionMQ.addEventListener) {
        _reduceMotionMQ.addEventListener('change', function(e){ _reduceMotion = e.matches; });
    }
    function _isSmallViewport(){ return (typeof window !== 'undefined') && window.innerWidth < 768; }
    var _lastFrame = 0;

    function tick(ts) {
        /* reduced motion: render one frame and stop the loop entirely */
        if (_reduceMotion && lastTime) { return; }
        /* small viewports: throttle to ~30fps */
        if (_isSmallViewport()) {
            if (ts - _lastFrame < 33) { animId=requestAnimationFrame(tick); return; }
            _lastFrame = ts;
        }
        if(!lastTime) lastTime=ts;
        var dt=Math.min(ts-lastTime,50);
        lastTime=ts;

        if(!(typeof weatherPinned!=='undefined'&&weatherPinned)) eventTimer+=dt;
        if(eventTimer>=EVENT_DURATION){
            eventTimer=0;
            eventIndex=(eventIndex+1)%EVENTS.length;
            initEvent(effType(EVENTS[eventIndex]));
            cityBuilt=false;
        }

        winFlickerT+=dt;
        if(winFlickerT>=WIN_FLICKER_INT){winFlickerT=0;flickerWindows();}

        updateParticles(dt);
        updateVehicles(dt);
        updatePeds(dt);
        if(airplane){
            airplane.t+=dt;
            airplane.strobT+=dt;
            airplane.x+=airplane.dir*dt*0.60;
            /* gentle sine-wave altitude variation */
            var targetY=airplane.baseY+Math.sin(airplane.t*0.00042)*H*0.028;
            airplane.y+=(targetY-airplane.y)*0.04;
            /* store contrail position every ~14ms */
            if(!airplane._lastTrail||airplane.t-airplane._lastTrail>14) {
                airplane._lastTrail=airplane.t;
                airplane.trail.push({x:airplane.x,y:airplane.y,age:0});
            }
            /* age and prune contrail */
            for(var tri=0;tri<airplane.trail.length;tri++) airplane.trail[tri].age+=dt;
            while(airplane.trail.length>0&&airplane.trail[0].age>5000) airplane.trail.shift();
            if(!airplane.switched&&airplane.x>W/2){
                currentCityIndex=airplane.nextCity;
                buildBgBuildings();
                buildLandmarks();
                cityBuilt=false;
                cityLabelTimer=3000;
                /* fresh city — wipe every trace of prior destruction */
                wreckage=[];
                craters=[];
                debrisParts=[];
                explosions=[];
                smokePlumes=[];
                missiles=[];
                interceptors=[];
                laserBeams=[];
                targetLocks=[];
                mushroomClouds=[];
                fireFields=[];
                gasClouds=[];
                empPulses=[];
                gravityWells=[];
                neutronPulses=[];
                antimatterBursts=[];
                photonStrikes=[];
                screenFlash=0;
                initVehicles();
                initPeds();
                initAirDefence();
                airplane.switched=true;
            }
            if(airplane.x>W+200||airplane.x<-200) airplane=null;
        }
        if(cityLabelTimer>0) cityLabelTimer-=dt;

        drawBg();
        drawCity();
        drawDynamic();

        ctx.clearRect(0,0,W,H);
        var evType=effType(EVENTS[eventIndex]);
        ctx.drawImage(bgCvs,0,0);
        /* Earthquake shakes the BUILDINGS (cityCvs) but not the sky.
           Vehicles + peds shake individually inside dynCvs via their own xShake/yOff. */
        if(evType==='earthquake') {
            ctx.drawImage(cityCvs, eqShakeX, eqShakeY);
        } else {
            ctx.drawImage(cityCvs,0,0);
        }
        ctx.drawImage(dynCvs,0,0);

        /* film grain */
        ctx.fillStyle='rgba(0,0,0,'+rng(0.010,0.022)+')';
        ctx.fillRect(0,0,W,H);

        animId=requestAnimationFrame(tick);
    }

    /* ── init ── */
    resize();
    buildBgBuildings();
    buildStarField();
    buildLandmarks();
    initVehicles();
    initPeds();
    initAirDefence();
    initEvent(effType(EVENTS[eventIndex]));

    window.addEventListener('resize',function(){
        resize();
        buildBgBuildings();
        buildStarField();
        buildLandmarks();
        initAirDefence();   /* keep batteries positioned at current width */
        cityBuilt=false;
    });

    animId=requestAnimationFrame(tick);

    window.switchCity=function(){
        if(airplane) return;
        var next=(currentCityIndex+1)%CITIES.length;
        var baseY=GROUND*0.22;
        airplane={x:-160,y:baseY,dir:1,nextCity:next,switched:false,
                  t:0, baseY:baseY, strobT:0, trail:[]};
        var btn=document.getElementById('citySwitchBtn');
        if(btn) btn.removeAttribute('title');
    };
    window.getCityName=function(){ return CITIES[currentCityIndex].name; };
    window.getNextCityName=function(){ return CITIES[(currentCityIndex+1)%CITIES.length].name; };
    window.getCurrentCityIndex=function(){ return currentCityIndex; };
    window.getAllCities=function(){
        return CITIES.map(function(c,i){ return { index:i, name:c.name }; });
    };
    /* fly to a specific city by index */
    window.flyToCity=function(targetIdx){
        if(airplane) return;
        if(typeof targetIdx!=='number' || targetIdx<0 || targetIdx>=CITIES.length) return;
        if(targetIdx===currentCityIndex) return;
        var baseY=GROUND*0.22;
        airplane={x:-160,y:baseY,dir:1,nextCity:targetIdx,switched:false,
                  t:0, baseY:baseY, strobT:0, trail:[]};
        var btn=document.getElementById('citySwitchBtn');
        if(btn) btn.removeAttribute('title');
    };

